(function(w){w.__PC_DUOC_CHUNKS=w.__PC_DUOC_CHUNKS||{};w.__PC_DUOC_CHUNKS["jci-05"]=[{"c":"GLD.09.00","ch":"GLD","t":"Nghiên cứu đối tượng con người, khi được thực hiện trong bệnh viện, được hướng dẫn bởi luật pháp, quy định và các nhà lãnh đạo bệnh viện.","p":"Nghiên cứu đối tượng là con người là một nỗ lực phức tạp và quan trọng đối với một bệnh viện. Các nhà\nlãnh đạo bệnh viện nhận ra mức độ cam kết và sự tham gia cá nhân cần thiết để thúc đẩy nghiên cứu khoa\nhọc. Với các quy định khác nhau của địa phương, các nhà lãnh đạo bệnh viện phải bảo vệ bệnh nhân và tôn\ntrọng quyền của họ trong quá trình nghiên cứu, điều tra và thử nghiệm lâm sàng.\n\nCam kết của bệnh viện đối với nghiên cứu đối tượng là con người không tách biệt với cam kết chăm sóc\nbệnh nhân của bệnh viện—cam kết được tích hợp ở mọi cấp độ. Do đó, các cân nhắc về đạo đức, giao tiếp\nhiệu quả, các nhà lãnh đạo có trách nhiệm, tuân thủ quy định và các nguồn lực tài chính và phi tài chính là\ncác thành phần của cam kết này. Một trong những nguồn lực đó là bảo hiểm bồi thường để bồi thường\ncho bệnh nhân về các sự kiện bất lợi do giao thức nghiên cứu gây ra. Các nhà lãnh đạo bệnh viện nhận ra\nnghĩa vụ bảo vệ bệnh nhân bất kể nhà tài trợ của nghiên cứu là ai.\n\nCác cá nhân từ chương trình nghiên cứu hoặc các chương trình khác tham gia vào việc xây dựng các tiêu chí\nhoặc giao thức. Việc nhập viện vào các chương trình như vậy được ghi lại trong hồ sơ y tế của bệnh\nnhân và bao gồm các điều kiện tiêu chí hoặc giao thức mà bệnh nhân được nhập viện.\n\nĐể tuân thủ luật pháp và quy định của địa phương, bệnh viện thành lập một ủy ban hoặc xác định một\nhoặc nhiều cá nhân đủ điều kiện để giám sát tất cả các nghiên cứu trong bệnh viện liên quan đến đối tượng\nlà con người. Một ủy ban hoặc cơ chế khác như Hội đồng Đánh giá Thể chế (IRB) chung hoặc dành riêng\ncho bệnh viện để giám sát tất cả các hoạt động như vậy trong bệnh viện được thành lập. Bệnh viện xây\ndựng một tuyên bố về mục đích cho các hoạt động giám sát. Các hoạt động giám sát bao gồm quy trình đánh\ngiá cho tất cả các giao thức nghiên cứu, quy trình cân nhắc các rủi ro và lợi ích tương đối cho các đối tượng\nvà các quy trình liên quan đến tính bảo mật và an toàn của thông tin nghiên cứu.\n\nGovernance, Leadership,\n\nCác yếu tố đo lường được của GLD.09.00\n1.\nLãnh đạo bệnh viện xác định các viên chức chịu trách nhiệm phát triển và tuân thủ các chính sách\nnghiên cứu đối tượng là con người phù hợp với các yêu cầu về mặt chuyên môn và quy định.\n2.\nĐể giúp bệnh nhân xác định có nên tham gia nghiên cứu, điều tra hoặc thử nghiệm lâm sàng hay\nkhông, bệnh viện cung cấp cho bệnh nhân tất cả các thông tin sau:\n•\nGiải thích về mục đích và phạm vi nghiên cứu\n•\nThời gian dự kiến bệnh nhân tham gia\n•\nMô tả rõ ràng về các thủ tục cần tuân theo\n•\nTuyên bố về các lợi ích, rủi ro, khó chịu và tác dụng phụ tiềm ẩn\n•\nChăm sóc thay thế, điều trị và các dịch vụ có sẵn cho bệnh nhân có thể chứng minh là có lợi\n•\ncho bệnh nhân\n3.\nBệnh viện ghi lại những điều sau đây trong mẫu đơn đồng ý nghiên cứu:\n•\nBệnh nhân đã nhận được thông tin để giúp xác định có nên tham gia nghiên cứu,\n•\nđiều tra hoặc thử nghiệm lâm sàng hay không\n•\nBệnh nhân đã được thông báo rằng việc từ chối tham gia nghiên cứu, điều tra hoặc\n•\nthử nghiệm lâm sàng hoặc ngừng tham gia bất kỳ lúc nào sẽ không gây nguy hiểm cho quyền tiếp\ncận dịch vụ chăm sóc, điều trị và các dịch vụ không liên quan đến nghiên cứu\n•\nTên của người cung cấp thông tin và ngày ký mẫu đơn\n•\nQuyền của bệnh nhân được quyền riêng tư, tính bảo mật và an toàn (Xem thêm PCC.01.02, ME\n1)\n4.\nLãnh đạo bệnh viện đảm bảo có nguồn bảo hiểm bồi thường để bồi thường cho bệnh nhân tham gia\nnghiên cứu lâm sàng gặp phải sự kiện bất lợi.\n5.\nGiám sát các hoạt động nghiên cứu trên đối tượng là con người bao gồm các quy trình để đảm bảo\ntính bảo mật và an toàn của thông tin nghiên cứu.\n\nCông nghệ chăm sóc\nsức khoẻ\n\nTổng quan\nNgành chăm sóc sức khỏe đang phải đối mặt với một cuộc cách mạng kỹ thuật số đang diễn ra nhanh chóng. Các\nbệnh viện đang áp dụng các phương pháp công nghệ mới để hợp lý hóa các quy trình và thủ tục và giảm chi phí. Từ\nhồ sơ sức khỏe điện tử (EHR) đến khả năng chăm sóc sức khỏe từ xa, trí tuệ nhân tạo (AI) và những tiến bộ về\nthiết bị y tế, những cải tiến về công nghệ đã nâng cao kết quả lâm sàng, cải thiện việc chăm sóc bệnh nhân và biến\nđổi các khả năng cung cấp dịch vụ chăm sóc.\n\nKhi nhu cầu về các dịch vụ chăm sóc sức khỏe chuyên khoa tiếp tục tăng, công nghệ sẽ tiếp tục đóng vai trò quan\ntrọng và cần thiết trong quy trình chăm sóc toàn diện. Quản lý công nghệ và thiết bị y tế đòi hỏi mức độ giao tiếp và\ncộng tác cao để duy trì một hệ thống chăm sóc, dịch vụ và nhà cung cấp tích hợp tạo nên chuỗi chăm sóc. Việc thiết\nlập các quy trình và thủ tục để tích hợp và giám sát hiệu quả là tối quan trọng để thành công.\n\nTiêu chuẩn\nSau đây là danh sách tất cả các tiêu chuẩn cho chức năng này. Chúng được trình bày ở đây để thuận tiện cho bạn mà\nkhông có các tuyên bố ý định hoặc các yếu tố có thể đo lường. Để biết thêm thông tin về các tiêu chuẩn này, vui lòng\nxem phần tiếp theo trong chương này, Tiêu chuẩn, Ý định và","m":[],"sec":"Nghiên cứu đối tượng con người"},{"c":"HCT.01.00","ch":"HCT","t":"Lãnh đạo bệnh viện xác định một cá nhân đủ tiêu chuẩn để giám sát công nghệ thông tin y tế và các quy trình của bệnh viện.","p":"Hệ thống công nghệ có thể phức tạp và cần giám sát để triển khai thành công và phối hợp với các quy\ntrình hiện có.\nĐầu tư vào công nghệ thông tin là nguồn lực quan trọng đối với các hệ thống bệnh viện. Hệ thống và\nquy trình công nghệ có thể cải thiện đáng kể hiệu quả, sự an toàn của bệnh nhân, việc phổ biến dữ\nliệu và giảm lỗi.\nCông nghệ thông tin y tế bao gồm:\n•\nHồ sơ sức khỏe điện tử để ghi chép và chia sẻ thông tin\n•\nCổng thông tin bệnh nhân\n•\nNền tảng trao đổi thông tin y tế\n•\nHệ thống lưu trữ, quản lý và bảo mật dữ liệu\n•\nNền tảng giao tiếp giữa các bác sĩ chăm sóc sức khỏe để phối hợp chăm sóc\n•\nGiao diện với các hệ thống khác để tạo điều kiện thuận lợi cho việc chăm sóc và điều trị bệnh nhân\n•\nCông cụ kê đơn điện tử\n•\nCông nghệ và ứng dụng chăm sóc sức khỏe từ xa\n•\nPhần mềm lập hóa đơn y tế\nNếu không được đánh giá và thử nghiệm đúng cách, công nghệ thông tin y tế có thể gây ra nhiều rủi\nro hơn cho bệnh nhân. Việc triển khai và tích hợp thành công các hệ thống công nghệ thông tin y tế\nđòi hỏi nguồn lực và chỉ đạo từ các nhà lãnh đạo bệnh viện. Nhóm lãnh đạo chỉ định một cá nhân đủ\nđiều kiện để giám sát các hệ thống và quy trình công nghệ. Một cá nhân đủ điều kiện có trình độ học\nvấn, đào tạo và/hoặc kinh nghiệm liên quan đến vai trò và trách nhiệm.\nHệ thống công nghệ thông tin của bệnh viện phải được quản lý hiệu quả, toàn diện và có sự phối hợp.\nCá nhân giám sát hệ thống công nghệ thông tin y tế chịu trách nhiệm ít nhất về những điều sau:\n•\nĐề xuất không gian, thiết bị, công nghệ và các nguồn lực khác cho các nhà lãnh đạo bệnh viện để hỗ\ntrợ hệ thống công nghệ thông tin trong bệnh viện\n•\nLựa chọn và thử nghiệm các công nghệ/hệ thống mới\n•\nTiến hành đánh giá rủi ro để đánh giá rủi ro bảo mật, ưu tiên rủi ro và xác định các cải tiến\n•\nĐảm bảo rằng nhân viên được đào tạo và giáo dục về bảo mật công nghệ, các chính sách và quy trình\náp dụng\n•\nTriển khai các số liệu để đánh giá cách thức hệ thống công nghệ đang hoạt động và tác động đến hoạt\nđộng của bệnh viện\nKhi triển khai hệ thống công nghệ, điều quan trọng là bệnh viện phải thiết lập một quy trình để đánh\ngiá khả năng sử dụng và hiệu quả của chúng. Đánh giá bao gồm những điều sau:\n•\nCông nghệ có được sử dụng theo đúng thiết kế và mục đích hay không\n•\nCông nghệ tích hợp tốt như thế nào với các công nghệ hiện có\n•\nCông nghệ có tác động gì đến việc cải thiện sự an toàn của bệnh nhân, giảm lỗi và nâng cao hiệu suất\n•\nCông nghệ có tác động gì đến nhân viên (ví dụ: tăng hiệu quả, tăng hoặc giảm căng thẳng\n•\nvà kiệt sức)\n\n(hC )\n\nTùy thuộc vào quy mô và phạm vi của bệnh viện, có thể có một số cá nhân hỗ trợ người phụ trách quản lý các\nkhía cạnh của chương trình. Cá nhân này cũng có thể có trách nhiệm với các hệ thống thông tin y tế.\n\nToàn bộ hoặc một phần việc tích hợp công nghệ thông tin y tế mới và hiện có có thể được thực hiện thông qua\ncác dịch vụ theo hợp đồng. Việc giám sát hợp đồng được thực hiện bởi cá nhân giám sát công nghệ thông tin y\ntế hoặc quản lý thông tin y tế.\n\nCác yếu tố đo lường được của HCT.01.00\n1.\nLãnh đạo bệnh viện cung cấp hỗ trợ và nguồn lực cho các dịch vụ công nghệ trong bệnh viện.\n2.\nLãnh đạo bệnh viện xác định một cá nhân đủ điều kiện để giám sát các hệ thống và quy trình công nghệ. (Xem\nthêm GLD.06.00, ME 1)\n3.\nD Lãnh đạo bệnh viện và một hoặc nhiều cá nhân đủ điều kiện tham gia vào các quy trình như lựa chọn, thử\nnghiệm, triển khai và đánh giá các hệ thống công nghệ thông tin y tế mới và đang phát triển.\n4.\nCác hệ thống công nghệ thông tin y tế mới và đang phát triển được theo dõi và đánh giá về khả năng sử dụng, hiệu\nquả, mục đích sử dụng của nhân viên và sự an toàn của bệnh nhân, đồng thời các cải tiến được xác định và triển khai\ndựa trên kết quả.","m":[],"sec":"Công nghệ thông tin trong chăm sóc sức khỏe"},{"c":"HCT.01.01","ch":"HCT","t":"Khi dữ liệu và thông tin của bệnh nhân được gửi qua phương tiện điện tử, qua thiết bị di động hoặc các hình thức liên lạc điện tử khác, bệnh viện sẽ thực hiện các quy trình để đảm bảo chất lượng chăm sóc bệnh nhân, tuân thủ luật pháp và quy định của địa phương, đồng thời duy trì tính bảo mật và an toàn của thông tin bệnh nhân.","p":"Dữ liệu nhạy cảm về thời gian được gửi qua đường điện tử có thể không được bác sĩ xem kịp thời và làm chậm trễ\ncác hành động ngay lập tức có thể cần thiết. Thông tin có thể được bảo mật ở phía bác sĩ hoặc bệnh viện, nhưng\nbệnh nhân có thể không có cùng các biện pháp bảo mật tại chỗ.\n\nKhi công nghệ phát triển, nhiều bác sĩ chăm sóc sức khỏe đã bắt đầu sử dụng các hình thức giao tiếp điện tử để thực\nhiện các mục đích sau:\n• Truyền đạt dữ liệu và thông tin của bệnh nhân qua tin nhắn văn bản và email (kết quả quan trọng, giới thiệu và\nghi chú).\n• Trao đổi thông tin với các bác sĩ khác.\n• Nhận tin nhắn văn bản hoặc email từ bệnh nhân.\nCác hình thức giao tiếp điện tử này có thể bao gồm thiết bị di động, email và nền tảng nhắn tin an toàn. Bệnh viện\ncó thể cung cấp thiết bị di động hoặc cầm tay cho bác sĩ chăm sóc sức khỏe của mình hoặc có thể cho phép bác sĩ sử\ndụng thiết bị cá nhân của họ. Khi sử dụng thiết bị di động hoặc cầm tay, bệnh viện cần đảm bảo dữ liệu và thông tin\ncủa bệnh nhân được bảo mật và giữ bí mật, theo luật pháp và quy định cũng như chính sách của bệnh viện. Khi\nbệnh viện cung cấp các thiết bị này cho nhân viên, sẽ có các quy trình để thu hồi thiết bị khi nhân viên không còn làm\nviệc hoặc không còn liên quan đến bệnh viện.\n\nKhi bệnh viện cho phép truyền thông tin bệnh nhân bí mật và riêng tư qua tin nhắn văn bản (ví dụ: thông tin nhận\ndạng bệnh nhân, chẩn đoán, tiền sử, kết quả xét nghiệm, thông tin bí mật khác), bệnh viện đảm bảo triển khai nền\ntảng nhắn tin chính thức, an toàn và bao gồm các nội dung sau:\n• Quy trình đăng nhập an toàn, được mã hóa để xác thực người dùng (được bảo vệ bằng mật khẩu, duy nhất cho\nmỗi người dùng và được mã hóa đầu cuối cho tất cả nội dung)\n\n(hC )\n\n•\nQuy trình đảm bảo chỉ những cá nhân được ủy quyền mới có trong danh mục nền tảng để nhận tin nhắn\n•\nBiên lai gửi và đã đọc tin nhắn\n•\nDấu ngày và giờ cho tin nhắn\n•\nQuy trình bảo vệ và bảo mật thông tin bệnh nhân khỏi việc truy cập và sử dụng trái phép\n\nNếu không thể đảm bảo nội dung tin nhắn được an toàn, thông tin bí mật phải được loại trừ khỏi tin nhắn.\nKhông được gửi thông tin nhạy cảm của bệnh nhân qua nền tảng kém an toàn hơn.\n\nBệnh viện thiết lập quy trình đảm bảo rằng email hoặc tin nhắn văn bản có thông tin bệnh nhân được ghi lại\ntrong hồ sơ y tế khi nội dung liên quan đến việc chăm sóc bệnh nhân. Ví dụ, tin nhắn văn bản được trao đổi\ngiữa các bác sĩ chăm sóc sức khỏe có chứa thông tin được sử dụng để đưa ra quyết định về việc chăm sóc bệnh\nnhân cần được ghi lại trong hồ sơ y tế của bệnh nhân đó.\n\nCổng thông tin bệnh nhân cũng cho phép giao tiếp giữa bác sĩ và bệnh nhân và cung cấp nhiều dịch vụ có thể\nthực hiện trực tuyến hoặc thông qua ứng dụng trên thiết bị di động, chẳng hạn như sau:\n• Hoàn thành biểu mẫu đăng ký\n• Yêu cầu nạp đơn thuốc\n• Truy cập kết quả xét nghiệm\n• Lên lịch các cuộc hẹn không khẩn cấp\n• Gửi/nhận tin nhắn với bác sĩ\n• Tải xuống tài liệu giáo dục\n• Thực hiện thanh toán điện tử\n\nCác bệnh viện triển khai cổng thông tin bệnh nhân đảm bảo tính bảo mật và an toàn cho thông tin bệnh nhân\nđược lưu trữ và trao đổi thông qua cổng thông tin. Việc triển khai và sử dụng cổng thông tin bệnh nhân yêu cầu\nmã hóa dữ liệu/thông tin bệnh nhân, quy trình đăng nhập an toàn, được mã hóa với yêu cầu mật khẩu cho người\ndùng, theo dõi kiểm toán\nghi lại và lưu lại các hoạt động chính và sự đồng ý của bệnh nhân để tham gia vào cổng thông tin bệnh nhân.\n\nCó thể đạt được tính bảo mật dữ liệu theo nhiều cách, bao gồm:\n• Triển khai kiểm soát truy cập bằng xác thực\n• Thiết lập chính sách mật khẩu an toàn theo quy định của bệnh viện (ví dụ: số lượng ký tự tối thiểu, sử dụng ký\ntự đặc biệt, kết hợp chữ cái và số, sử dụng chữ hoa và chữ thường, hạn chế sử dụng lại mật khẩu trước đó,\nlịch trình gia hạn mật khẩu trong suốt cả năm)\n• Triển khai truy cập từ xa để vô hiệu hóa hoặc xóa dữ liệu bệnh nhân khỏi thiết bị di động trong trường hợp\nchúng bị mất hoặc bị đánh cắp\n• Tăng cường kiểm soát bảo mật\n• Hạn chế sử dụng email ở những khu vực có nguy cơ vi phạm tính bảo mật hoặc chậm trễ phản hồi thấp hơn\n\nBệnh viện triển khai quy trình theo dõi chất lượng thông tin liên lạc được thực hiện qua tin nhắn văn bản, email\nvà cổng thông tin bệnh nhân, đồng thời cải thiện khi cần thiết. Bệnh viện đảm bảo rằng bệnh nhân hiểu đầy đủ\nvề dữ liệu và thông tin nhận được qua tin nhắn văn bản, email và cổng thông tin bệnh nhân, đồng thời khuyến\nkhích bệnh nhân liên hệ với nhà cung cấp dịch vụ chăm sóc sức khỏe của họ để được giải đáp thắc mắc. Bệnh\nviện thu thập dữ liệu để theo dõi quy trình nhằm làm rõ các câu hỏi phát sinh từ tin nhắn nhận được qua tin\nnhắn văn bản, email và cổng thông tin bệnh nhân. Ví dụ, bệnh viện có thể thu thập dữ liệu về tần suất nhân viên\ncần làm rõ thông tin bệnh nhân đã được nhắn tin và quy trình để có được sự làm rõ. Khi áp dụng, bệnh viện tuân\nthủ các quy tắc hoặc tiêu chuẩn quản lý thông tin y tế do quốc gia/khu vực nơi bệnh viện hoạt động đặt ra.\n\n(hC )\n\nCác yếu tố đo lường được của HCT.01.01\n1.\nKhi dữ liệu và thông tin bệnh nhân được truyền qua tin nhắn văn bản di động hoặc các công cụ truyền\nthông điện tử, bệnh viện đảm bảo rằng quy trình này được thực hiện thông qua một nền tảng an toàn và\ntuân thủ các điều sau:\n• Quy trình đăng nhập an toàn, được mã hóa để xác thực người dùng (được bảo vệ bằng mật khẩu và\nduy nhất cho mỗi người dùng)\n• Quy trình đảm bảo rằng chỉ những cá nhân được ủy quyền mới có trong danh mục nền tảng để nhận\ntin nhắn\n• Biên lai gửi và đã đọc cho tin nhắn\n• Dấu ngày và giờ cho tin nhắn\n• Quy trình bảo vệ và bảo mật thông tin bệnh nhân khỏi việc truy cập và sử dụng trái phép\n(Xem thêm MOI.01.02, ME 3)\n2.\nKhi sử dụng thiết bị di động để truyền dữ liệu và thông tin bệnh nhân, bệnh viện triển khai các hướng\ndẫn và quy trình bằng văn bản để bảo vệ và bảo mật thông tin bệnh nhân. (Xem thêm MOI.01.02, ME 3)\n3.\nBệnh viện thiết lập các quy trình để đảm bảo rằng thông tin liên quan đến việc chăm sóc bệnh nhân được\ngửi bằng phương tiện điện tử (ví dụ: qua tin nhắn văn bản hoặc email) được ghi lại trong hồ sơ y tế\ncủa bệnh nhân. (Xem thêm MOI.03.00, ME 4)\n4.\nKhi bệnh viện triển khai cổng thông tin bệnh nhân hoặc giao tiếp với bệnh nhân qua tin nhắn văn bản\nhoặc email, bệnh viện thực hiện các bước sau:\n• Giáo dục bệnh nhân về cổng thông tin bệnh nhân và xác nhận sự sẵn sàng sử dụng. (Xem thêm\nPCC.04.00, ME 1)\n• Nhận được sự đồng ý của bệnh nhân để tham gia vào cổng thông tin và/hoặc nhận tin nhắn văn bản\nhoặc email.\n5.\nKhi bệnh viện cho phép thông tin bệnh nhân được truyền đạt qua tin nhắn văn bản, email và cổng thông\ntin bệnh nhân, bệnh viện có quy trình để đảm bảo rằng các câu hỏi phát sinh về thông tin được trao đổi\nđược giải quyết kịp thời và theo dõi các cải tiến cần thiết đối với quy trình giao tiếp.","m":[],"sec":"Công nghệ thông tin trong chăm sóc sức khỏe"},{"c":"HCT.01.02","ch":"HCT","t":"Đối với các bệnh viện cung cấp dịch vụ chăm sóc sức khỏe từ xa, bệnh viện thực hiện các hướng dẫn để bảo vệ dữ liệu và thông tin của bệnh nhân.","p":"Các hướng dẫn đã thiết lập cho dịch vụ chăm sóc sức khỏe từ xa cung cấp một khuôn khổ cho việc chuẩn hóa, an\ntoàn, bảo mật và chất lượng chăm sóc.\nChăm sóc sức khỏe từ xa đòi hỏi một phương pháp tiếp cận toàn diện và tích hợp hơn để cung cấp dịch vụ chăm\nsóc bệnh nhân. Mức độ hợp tác và giao tiếp cao giữa các nhà cung cấp dịch vụ chăm sóc sức khỏe là bắt buộc để\ntriển khai thành công.\nMột bệnh viện cung cấp dịch vụ chăm sóc sức khỏe từ xa nên thiết lập một khuôn khổ để cung cấp dịch vụ cho\nbệnh nhân theo cách nhất quán, bất kể bệnh nhân hoặc nhà cung cấp ở đâu. Việc có một quy trình chuẩn hóa để\ncung cấp dịch vụ sẽ mang lại phương pháp tốt nhất, sử dụng hiệu quả các nguồn lực và cải thiện kết quả cho\nbệnh nhân. Các nhà cung cấp hoạt động trong một hệ thống tích hợp sẽ đảm bảo \"cung cấp dịch vụ và chăm sóc\nliền mạch\". Các quy trình hiện có sẽ đảm bảo các biện pháp tích hợp để ngăn chặn tình trạng phân mảnh dữ liệu.\nDữ liệu và thông tin của bệnh nhân sẽ được nhập vào hồ sơ y tế trong quá trình khám trực tiếp phải được\nđưa vào hồ sơ y tế trong quá trình khám sức khỏe từ xa (ví dụ: tiền sử bệnh nhân, chẩn đoán, điều trị, hướng\ndẫn).\n\nBệnh viện triển khai các hướng dẫn để đảm bảo dữ liệu và thông tin của bệnh nhân được bảo mật và các dịch\nvụ chăm sóc sức khỏe từ xa được bảo mật khỏi các vi phạm dữ liệu và các mối đe dọa an ninh mạng khác. Điều\nnày bắt đầu bằng một chương trình đào tạo nhân viên hiệu quả.\n\n(hC )\n\nVi phạm dữ liệu có thể gây hại cho bệnh nhân và có thể dẫn đến các khoản tiền phạt cho tổ chức. Các bệnh viện sử\ndụng nền tảng chăm sóc sức khỏe từ xa nên triển khai các quy trình để đảm bảo dữ liệu là chính xác và được bảo mật\nđể ngăn chặn việc cung cấp dịch vụ chăm sóc không phù hợp. Các phương pháp có thể được sử dụng bao gồm:\n•\nXác thực đa yếu tố\n•\nLưu trữ dữ liệu phi tập trung\n•\nDữ liệu được mã hóa\n•\nSử dụng mạng an toàn hoặc mạng riêng ảo (VPN)\n•\nGiám sát kiểm soát truy cập\nCác chương trình đào tạo nhân viên phải bao gồm nhận thức về an ninh mạng với các chủ đề cụ thể đảm bảo an ninh\ncho thông tin bí mật.\nCác yếu tố đo lường được của HCT.01.02\n1.\nBệnh viện triển khai các hướng dẫn và quy trình bằng văn bản để bảo mật thông tin bệnh nhân khi sử dụng\ndịch vụ chăm sóc sức khỏe từ xa.\n2.\nBệnh viện thiết lập các quy trình để đảm bảo thông tin bệnh nhân được bảo mật khi sử dụng dịch vụ chăm sóc\nsức khỏe từ xa.\n3.\nBệnh viện thiết lập các quy trình để đảm bảo tích hợp thông tin khi sử dụng nhiều điểm tiếp xúc và nền tảng\ntrong hệ thống.\n4.\nTất cả nhân viên tham gia cung cấp dịch vụ chăm sóc sức khỏe từ xa đều được đào tạo về an ninh mạng và giáo\ndục liên tục, và đào tạo và giáo dục liên tục được ghi chép lại. Đào tạo cho nhân viên tiếp cận hệ thống công\nnghệ thông tin y tế bao gồm:\n•\nBảo mật thiết bị\n•\nQuyền truy cập\n•\nBảo vệ mật khẩu\n•\nKỹ thuật xã hội và lừa đảo\n•\nMối đe dọa an ninh mạng","m":[],"sec":"Công nghệ thông tin trong chăm sóc sức khỏe"},{"c":"HCT.01.03","ch":"HCT","t":"Đối với các bệnh viện sử dụng công cụ hỗ trợ quyết định lâm sàng trí tuệ nhân tạo, có các quy trình để lựa chọn, triển khai, giám sát và cải tiến.","p":"Công nghệ trí tuệ nhân tạo (AI) đang tiến triển nhanh chóng trong bối cảnh chăm sóc sức khỏe và đòi hỏi các\nhướng dẫn để đảm bảo tránh được sự thiên vị, duy trì các tiêu chuẩn đạo đức, thông tin được lưu trữ riêng tư và\nan toàn, và các công cụ hoạt động như mong đợi để đáp ứng kỳ vọng của người dùng cuối.\nNhững tiến bộ của AI đang tạo cơ hội cho các bệnh viện cải thiện kết quả, giảm chi phí tổ chức và tác động đến\nsức khỏe cộng đồng. Các công cụ hỗ trợ quyết định dựa trên AI đang được triển khai trên nhiều bối cảnh và\nchuyên khoa trong bối cảnh chăm sóc sức khỏe để chuyển đổi các quy trình ra quyết định. Các công cụ này được\nsử dụng để cải thiện chất lượng chăm sóc, tăng hiệu quả cung cấp dịch vụ chăm sóc và nâng cao khả năng ra\nquyết định bằng cách phân tích dữ liệu bệnh nhân và đưa ra dự đoán dựa trên dữ liệu đó. Học máy và thuật toán\nphân tích dữ liệu, học hỏi từ các mô hình hoặc xu hướng và cung cấp thông tin chi tiết cho các nhà cung cấp dịch\nvụ chăm sóc sức khỏe trên toàn bộ chuỗi liên tục.\nNgành chăm sóc sức khỏe là một trong số ít ngành mà khách hàng tìm kiếm trên Internet để tìm kiếm các vấn đề\ncủa họ trước khi tham khảo ý kiến của chuyên gia. Mọi người nghiên cứu các triệu chứng của họ trực tuyến và có\nxu hướng tự chẩn đoán dựa trên các kết quả tìm kiếm đó. Để đáp ứng nhu cầu ngày càng tăng về dịch vụ, việc sử\ndụng chatbot AI hoặc công nghệ tương tự đang gia tăng. Việc sử dụng AI theo cách này có thể cho phép cung cấp\ncác dịch vụ này cho nhiều đối tượng dân số hơn, tiết kiệm thời gian cho nhà cung cấp và tăng khả năng phân tích\ndữ liệu. Khi kết hợp chatbot, cần quan tâm đến việc dữ liệu vẫn được giữ riêng tư, được bảo vệ và được mã hóa\ntrong quá trình sử dụng.\nMột cá nhân đủ tiêu chuẩn, được xác định thông qua đào tạo và lý lịch có liên quan, cũng như nhóm lãnh đạo và\ncác bên liên quan chính, nên tham gia vào quá trình lựa chọn và giám sát liên tục các công cụ AI. Các bệnh viện sử\n\n(hC )\n\ndụng công nghệ AI nên có các phương pháp để đánh giá các công cụ hỗ trợ ra quyết định nhằm đảm bảo chúng đáp ứng\nđược kỳ vọng của bệnh viện và nhóm bệnh nhân. Việc giám sát liên tục là cần thiết đối với khả năng sử dụng, mục đích\nsử dụng, khả năng cập nhật, an toàn dữ liệu, chất lượng dữ liệu, rủi ro hệ thống và mọi mối quan ngại về đạo đức.\nCũng nên cân nhắc rằng một bác sĩ tham gia vào quá trình ra quyết định cuối cùng khi liên quan đến việc chăm sóc bệnh\nnhân. Các bác sĩ vẫn nên khám bệnh nhân, xem xét mọi lời nhắc trong tài liệu và chịu trách nhiệm chăm sóc bệnh nhân.\nBệnh viện nên thiết lập một quy trình để báo cáo bất kỳ kết quả bất lợi nào cho nhóm lãnh đạo và các bên liên quan\nchính.\nCần phải giáo dục và đào tạo tất cả các thành viên nhân viên có liên quan tương tác với các công cụ hỗ trợ ra quyết định\nAI để đảm bảo tích hợp hiệu quả và an toàn vào hoạt động thực hành và cung cấp dịch vụ chăm sóc. Việc có người\ndùng cố định tại chỗ để khắc phục sự cố hoặc cung cấp các buổi đào tạo có thể mang lại lợi ích cho tổ chức.\nCác công cụ hỗ trợ quyết định lâm sàng AI bao gồm các công cụ hỗ trợ quyết định chẩn đoán, công cụ hỗ trợ quyết\nđịnh điều trị, công cụ phân tích dự đoán và công cụ quản lý sức khỏe cộng đồng. Ví dụ về các loại công cụ hỗ trợ quyết\nđịnh lâm sàng thường được sử dụng trong bối cảnh bệnh viện bao gồm nhưng không giới hạn ở những công cụ sau:\n•\nCác tác nhân gây nhiễm trùng huyết\n•\nQuản lý vết thương\n•\nĐối chiếu thuốc\n•\nLiều dùng thuốc\n•\nLựa chọn mã chẩn đoán\n•\nHỗ trợ các quy trình phản ứng nhanh\n•\nTạo hướng dẫn điều trị cho các tình trạng khẩn cấp\n•\nGiải thích kết quả xét nghiệm và xét nghiệm\nCác yếu tố cần xem xét khi đánh giá công nghệ AI và thuật toán như sau:\n•\nNó có ý nghĩa hoặc hữu ích đối với bối cảnh không?\n•\nNó có cung cấp dữ liệu cập nhật không?\n•\nNó có đáp ứng được kỳ vọng về quy trình làm việc lâm sàng không?\n•\nTác động đến việc ra quyết định lâm sàng là gì?\n•\nMức độ tin cậy của dữ liệu đầu ra là bao nhiêu?\n•\nKhả năng xảy ra sai lệch là bao nhiêu?\nGiám sát việc sử dụng hiệu quả công nghệ AI để ra quyết định lâm sàng bao gồm các nội dung sau:\n•\nXem xét nhật ký sử dụng, bao gồm các mục đích sử dụng phổ biến, các lĩnh vực cần cải thiện và mức độ hài lòng\ncủa người dùng\n•\nXác định sự khác biệt trong chẩn đoán, khuyến nghị điều trị hoặc thuốc\n•\nPhân tích phản hồi từ nhà cung cấp\n•\nĐánh giá kết quả của bệnh nhân\n•\nThực hiện cập nhật công cụ hoặc hệ thống\nCác yếu tố đo lường được của HCT.01.03\n1. Bệnh viện xác định những cá nhân đủ tiêu chuẩn để lựa chọn các công cụ AI phù hợp cho các lĩnh vực chuyên\nmôn tương ứng của họ (ví dụ: dược, chăm sóc vết thương, phẫu thuật).\n2. Bệnh viện thiết lập các hướng dẫn và quy trình bằng văn bản để giám sát hiệu quả của các công cụ AI mà\nbệnh viện sử dụng. Bao gồm:\n• Quy trình phê duyệt và triển khai\n• Sự tham gia của bác sĩ vào quá trình ra quyết định cuối cùng về việc chăm sóc bệnh nhân\n• Bảo mật và quyền riêng tư của dữ liệu bệnh nhân (Xem thêm PCC.01.02, ME 1)\n• Xác định sự khác biệt của hệ thống\n• Phân tích từ các nhà cung cấp và các nguồn bên thứ ba có liên quan\n• Cập nhật phần mềm/công nghệ khi được coi là phù hợp\n• Các cân nhắc về đạo đức\n3. Bệnh viện theo dõi việc sử dụng và xu hướng liên tục và báo cáo kết quả cho các bên liên quan (ví dụ: các bên\nliên quan chính, nhóm lãnh đạo, các nguồn bên thứ ba).\n\n(hC )","m":[],"sec":"Công nghệ thông tin trong chăm sóc sức khỏe"},{"c":"HCT.01.04","ch":"HCT","t":"Bệnh viện phát triển, duy trì và thử nghiệm một chương trình để ứng phó với thời gian ngừng hoạt động theo kế hoạch và không theo kế hoạch của hệ thống dữ liệu.","p":"Hệ thống dữ liệu là một phần quan trọng trong việc cung cấp dịch vụ chăm sóc bệnh nhân an toàn, chất lượng cao\nvà thời gian ngừng hoạt động—có kế hoạch hay không—có thể ảnh hưởng đến toàn bộ hệ thống.\n\nBất kể bệnh viện có triển khai hồ sơ sức khỏe điện tử (EHR) hay không, thì một hình thức công nghệ thông tin vẫn tồn tại\nở phần lớn các bệnh viện. Công nghệ thông tin có thể được tìm thấy trong hình ảnh kỹ thuật số, xét nghiệm trong phòng thí\nnghiệm và báo cáo kết quả, hệ thống truyền thông, hệ thống hỗ trợ dược phẩm, v.v.\n\nGián đoạn và lỗi hệ thống dữ liệu, được gọi là thời gian ngừng hoạt động, là những sự kiện không thể tránh khỏi. Thời gian\nngừng hoạt động theo kế hoạch được lên lịch cho mục đích tiến hành bảo trì, sửa chữa, nâng cấp và các thay đổi khác đối\nvới hệ thống. Thời gian ngừng hoạt động không theo kế hoạch xảy ra do sự cố mất điện hoặc thiết bị, sự cố hệ thống sưởi\nấm/làm mát, thiên tai, lỗi của con người và gián đoạn dịch vụ Internet hoặc mạng nội bộ, trong số các sự cố gián đoạn khác.\nThời gian ngừng hoạt động không theo kế hoạch có thể dẫn đến lỗi hệ thống dữ liệu, chẳng hạn như mất dữ liệu, lỗi phần\ncứng và hỏng dữ liệu. Nó cũng có thể là kết quả của các mối đe dọa hoặc tấn công an ninh mạng. Bệnh viện có thể gặp nguy\ncơ mất dữ liệu vĩnh viễn nếu không có hệ thống sao chép và lưu trữ dữ liệu.\n\nBệnh viện phải chuẩn bị cho tất cả các khoa và dịch vụ đào tạo cụ thể về chiến thuật và biện pháp can thiệp để quản lý thời\ngian ngừng hoạt động trong lĩnh vực cụ thể của họ. Khi thời gian ngừng hoạt động không theo kế hoạch xảy ra, nhân viên\ncần được thông báo ngay khi phát hiện ra sự kiện.\n\nBệnh viện phải xây dựng các chiến lược và biện pháp để tiếp tục chăm sóc bệnh nhân trong thời gian gián đoạn hệ thống dữ\nliệu nhằm duy trì chất lượng và an toàn. Sau thời gian ngừng hoạt động, việc chăm sóc bệnh nhân và các dịch vụ được cung\ncấp trong thời gian ngừng hoạt động có thể cần phải được nhập thủ công, thông qua hệ thống quản lý/quét tài liệu hoặc\nthông qua việc sao chép từ bản cứng sang bản mềm trong thời gian không hoạt động.\n\nCác kế hoạch phục hồi nên được kiểm tra ít nhất một lần một năm. Các bản sao lưu đơn giản nên được kiểm tra ít nhất\nmột lần một quý và bất cứ khi nào có thay đổi lớn về phần cứng hoặc phần mềm trong hệ thống sao lưu. Điều quan trọng là\nphải chạy thử nghiệm sau khi nâng cấp để đảm bảo rằng bản nâng cấp hoạt động bình thường với các hệ thống còn lại.\n\nBệnh viện lập kế hoạch cho các gián đoạn bằng cách thực hiện các bước sau:\n•\nĐào tạo nhân viên về các quy trình thay thế\n•\nKiểm tra chương trình quản lý tình trạng khẩn cấp của bệnh viện\n•\nThực hiện sao lưu dữ liệu theo lịch trình thường xuyên\n•\nKiểm tra các quy trình khôi phục dữ liệu\n•\nXử lý các quy trình để đảm bảo tính liên tục với thông tin điện tử, thông tin trên giấy và/hoặc thông tin dựa trên kiến\nthức\n\nViệc giao tiếp là điều cần thiết để đảm bảo tính liên tục của việc chăm sóc trong thời gian ngừng hoạt động. Việc\nthông báo cho nhân viên về thời gian ngừng hoạt động theo kế hoạch cho phép họ thực hiện các biện pháp chuẩn bị\ncần thiết để đảm bảo rằng hoạt động kinh doanh vẫn tiếp tục theo cách an toàn và hiệu quả. Việc giao tiếp trước\nthời gian ngừng hoạt động theo kế hoạch phải bao gồm ít nhất các thông tin sau:\n•\nHệ thống hoặc ứng dụng công nghệ thông tin sẽ ngừng hoạt động và các phòng ban/khu vực dịch vụ sẽ bị ảnh hưởng\n•\nThời gian bắt đầu thời gian ngừng hoạt động và thời gian dự kiến hệ thống hoặc ứng dụng sẽ không khả dụng\n•\nLý do ngừng hoạt động và những thay đổi có thể xảy ra sau khi thời gian ngừng hoạt động theo kế hoạch hoàn tất\n(ví dụ: bảo trì thường xuyên mà không có thay đổi nào dự kiến hoặc cải tiến hệ thống)\n\nChiến thuật phục hồi thời gian chết phải bao gồm các hệ thống phục hồi thảm họa và chuyển đổi dự phòng để sao lưu,\nphục hồi và duy trì hệ thống dữ liệu. Các hệ thống phục hồi thường được đặt ở các vị trí từ xa để phục hồi dữ liệu có thể\n\n(hC )\n\nđã bị hỏng hoặc bị xóa ngoài ý muốn. Các hệ thống này phải được sao lưu định kỳ, thường là vào mỗi đêm. Các hệ\nthống dự phòng giảm thiểu gián đoạn trong việc chăm sóc bệnh nhân và mất dữ liệu và thường được triển khai tại\ncơ sở và được chuyển đổi trong vòng vài giây hoặc vài phút sau khi hệ thống chính không khả dụng do thời gian\nngừng hoạt động theo kế hoạch hoặc không theo kế hoạch. Trong các bệnh viện sử dụng hệ thống dựa trên đám\nmây để sao lưu dữ liệu, nhà cung cấp phải có các hệ thống sao lưu đầy đủ để giảm thiểu gián đoạn trong việc chăm\nsóc, ngăn ngừa mất dữ liệu và duy trì tính toàn vẹn của dữ liệu.\nCác bệnh viện có kế hoạch duy trì quyền truy cập vào các hệ thống thông tin điện tử bằng cách sử dụng nhiều quy\ntrình sao lưu và khôi phục khác nhau có khả năng sẽ trải nghiệm tính liên tục liền mạch của việc chăm sóc bệnh\nnhân và mất dữ liệu ở mức tối thiểu.\nCách thông tin được truyền đạt đến nhân viên phụ thuộc vào hệ thống bị ngừng hoạt động. Ví dụ: nếu mạng của\nbệnh viện bị ngừng hoạt động, có thể cần phải liên lạc với nhân viên qua điện thoại. Cần phát triển nhiều chiến\nlược truyền thông để giải quyết các hệ thống khác nhau có thể bị ảnh hưởng. Ngoài các chiến lược truyền thông\nnội bộ, có thể cần phải phát triển các chiến lược truyền thông bên ngoài. Ví dụ, nếu bệnh viện có ứng dụng giao\ndiện với các dịch vụ xét nghiệm hoặc X quang bên ngoài/theo hợp đồng và ứng dụng đó không khả dụng do thời\ngian ngừng hoạt động, cần phải có quy trình để lấy kết quả trong thời gian ngừng hoạt động và có kế hoạch báo\ncáo kết quả qua giao diện khi thời gian ngừng hoạt động kết thúc.\nMột cách tiếp cận để quản lý thời gian ngừng hoạt động là thực hành có một gói biểu mẫu thời gian ngừng hoạt\nđộng bản cứng hoặc một tập hồ sơ thời gian ngừng hoạt động để tiếp tục chăm sóc nếu thời gian ngừng hoạt động\nkhông theo kế hoạch vượt quá ngưỡng thời gian nhất định (thường lớn hơn 30 phút). Một cách tiếp cận khác là\nduy trì máy tính thời gian ngừng hoạt động cho phép truy cập chỉ đọc vào dữ liệu bệnh nhân.\nBệnh viện cần xác định dữ liệu nào có thể cần nhập lại theo định dạng riêng biệt (ví dụ: tất cả các loại thuốc được\nkê đơn trong thời gian ngừng hoạt động, các đơn thuốc đã chọn, dị ứng, danh sách vấn đề), dữ liệu nào có thể cần\nquét và dữ liệu nào có thể cần sao chép từ bản cứng sang bản mềm. Để đảm bảo tính bảo mật và an toàn của thông\ntin, bệnh viện nên có quy trình được lập thành văn bản để quản lý mọi tài liệu giấy được sử dụng trong thời gian\nngừng hoạt động.\nCó nhiều công cụ để sao lưu dữ liệu. Các giải pháp sao lưu tối ưu cho mỗi bệnh viện phụ thuộc vào nhiều yếu tố,\nbao gồm lượng dữ liệu cần sao lưu, tốc độ sao lưu và phục hồi dữ liệu, vị trí của hệ thống phục hồi, chi phí và các\nyếu tố khác.\n\nCác yếu tố đo lường được của HCT.01.04\n1.\nBệnh viện duy trì và kiểm tra ít nhất hàng năm một chương trình bằng văn bản để ứng phó với thời gian\nngừng hoạt động theo kế hoạch và không theo kế hoạch của các hệ thống dữ liệu. (Xem thêm FMS.08.00,\nME 1; HCT.01.05, ME 1)\n2.\nBệnh viện xác định tác động có thể xảy ra mà thời gian ngừng hoạt động theo kế hoạch và không theo kế\nhoạch của các hệ thống dữ liệu sẽ gây ra cho mọi khía cạnh của việc chăm sóc và dịch vụ.\n3.\nChương trình bao gồm các chiến lược liên tục để cung cấp dịch vụ và chăm sóc bệnh nhân an toàn, chất\nlượng cao đang diễn ra, bao gồm các dịch vụ do các nhà cung cấp bên ngoài cung cấp, trong thời gian ngừng\nhoạt động theo kế hoạch và không theo kế hoạch của các hệ thống dữ liệu.\n4.\nChương trình xác định các chiến lược truyền thông nội bộ và, khi áp dụng, bên ngoài cho thời gian ngừng\nhoạt động theo kế hoạch và không theo kế hoạch.\n5.\nBệnh viện triển khai các chiến thuật phục hồi thời gian ngừng hoạt động và các quy trình sao lưu dữ liệu\nđang diễn ra để phục hồi và duy trì dữ liệu, đảm bảo tính toàn vẹn của dữ liệu và duy trì tính bảo mật và an\ntoàn của thông tin bệnh nhân.\n6.\nNhân viên được đào tạo về các chiến lược và chiến thuật được sử dụng cho thời gian ngừng hoạt động theo\nkế hoạch và không theo kế hoạch của các hệ thống dữ liệu.","m":[],"sec":"Công nghệ thông tin trong chăm sóc sức khỏe"},{"c":"HCT.01.05","ch":"HCT","t":"Bệnh viện phát triển và duy trì các quy trình và thủ tục cho an ninh mạng và quản lý rủi ro mạng.","p":"Các cuộc tấn công mạng trong chăm sóc sức khỏe mang lại nhiều rủi ro hơn do loại thông tin và việc sử dụng thông tin rộng\nrãi và có thể gây bất lợi cho sự an toàn của bệnh nhân và hoạt động của bệnh viện nếu không được quản lý đúng cách.\n\nCác cuộc tấn công mạng có khả năng làm gián đoạn và trì hoãn nhiều dịch vụ khác nhau trong toàn bộ hệ thống bệnh viện,\nbao gồm vận chuyển xe cứu thương, phẫu thuật, cung cấp thuốc và hoạt động hệ thống (HVAC), v.v. Công nghệ thông tin,\ndù ở dạng hồ sơ sức khỏe điện tử (EHR) hay được sử dụng trong toàn bộ hệ thống bệnh viện, đều dễ bị tấn công mạng.\nKhi công nghệ tiến bộ trong hệ thống, các tiến bộ về an ninh mạng cũng cần được thực hiện để đảm bảo an toàn cho bệnh\nnhân và ngăn ngừa sự chậm trễ trong hoạt động. Các lĩnh vực dễ bị tấn công mạng bao gồm nhưng không giới hạn ở những\nlĩnh vực sau:\n• EHR\n• Phần mềm kê đơn điện tử\n• Theo dõi bệnh nhân từ xa\n• Hệ thống thông tin phòng xét nghiệm\n• Phần mềm lập hóa đơn y tế\n• Phần mềm lập lịch\n• Hệ thống truyền thông\n\nCác biện pháp và quy trình về an ninh mạng là cần thiết để bảo vệ thông tin có giá trị của bệnh nhân trong các cuộc tấn công.\nVí dụ, có thể sử dụng thử nghiệm xâm nhập để mô phỏng nhiều cuộc tấn công khác nhau bằng các công cụ tương tự mà kẻ\ntấn công mạng sẽ sử dụng để tìm điểm yếu trong hệ thống. Từ các kết quả thử nghiệm này, có thể xây dựng một chương\ntrình ứng phó.\n\nThời gian ngừng hoạt động liên quan đến các cuộc tấn công mạng đòi hỏi một kế hoạch khác biệt so với thời gian ngừng\nhoạt động theo kế hoạch hoặc không theo kế hoạch thông thường đối với các bệnh viện sử dụng hồ sơ sức khỏe điện tử và\nhệ thống liên lạc. Trong trường hợp xảy ra tấn công mạng, phải có quy trình báo cáo chi tiết cho bộ phận công nghệ thông\ntin (CNTT), lãnh đạo bệnh viện và nhóm an ninh mạng nếu có.\n\nHầu hết các khoa trong bệnh viện đều xử lý thông tin cực kỳ nhạy cảm và có giá trị đối với tin tặc mạng. Nhân viên, bao\ngồm nhà cung cấp dịch vụ chăm sóc, nhân viên thanh toán, nhân viên hành chính và nhân viên lập lịch, quản lý thông tin này\nhàng ngày và cần được đào tạo chuyên sâu để hiểu các biện pháp an toàn và hậu quả của một cuộc tấn công mạng hoặc vi\nphạm. Đào tạo ban đầu và liên tục nên được tiến hành và ghi lại để hoàn thành.\n\nTại nhiều bệnh viện, các nguồn lực được phân bổ cho bộ phận CNTT có thể bị hạn chế do một số hạn chế. Các nhà lãnh\nđạo phải xem xét tất cả các thiết bị y tế được kết nối với nhau trong toàn bộ hệ thống, hàng nghìn người sử dụng các thiết bị\nđó và các quy trình kinh doanh/người dùng không nhất quán.\n\nTrong trường hợp thời gian chết xảy ra do tấn công mạng, phải có các quy trình khôi phục thời gian chết để sao lưu, duy trì\nvà có khả năng khôi phục dữ liệu hệ thống. Không có cách duy nhất đúng để quản lý một cuộc tấn công mạng, nhưng việc\nlập kế hoạch trước có thể giảm thiểu tác động. Cả Viện Tiêu chuẩn và Công nghệ Quốc gia Hoa Kỳ (NIST) và Cơ quan An\nninh mạng Liên minh Châu Âu (ENISA) đều có khuôn khổ để thiết lập phương pháp tiếp cận dựa trên rủi ro.\n\nMột thế trận an ninh mạnh mẽ bao gồm những điều sau:\n• Có cơ sở hạ tầng và cơ sở ứng dụng ổn định, chất lượng cao (ví dụ: phần cứng, ứng dụng phần mềm, hệ điều hành, công\ncụ mạng và công cụ viễn thông)\n• Có cơ sở hạ tầng CNTT với quản lý cấu hình, quản lý thay đổi, ghi nhật ký và giám sát\n• Có lập trường chủ động và các biện pháp bảo mật tại chỗ (ví dụ: tài nguyên và lập ngân sách)\n• Đào tạo và nâng cao nhận thức cho tất cả nhân viên tương tác theo bất kỳ cách nào với công nghệ bệnh viện\n\nCác chiến lược để giảm thiểu nguy cơ bị tấn công mạng bao gồm nhưng không giới hạn ở những điều sau:\n• Lọc email và kiểm tra nội dung đáng ngờ\n• Cập nhật cấu hình bảo mật trên thiết bị, máy chủ và hệ thống\n• Cài đặt phần mềm diệt vi-rút\n\n(hC )\n\n• Chạy thử nghiệm thâm nhập\n• Hạn chế kiểm soát truy cập vật lý\n• Duy trì sao lưu theo lịch trình thường xuyên, được lưu trữ tại một vị trí ngoại tuyến, vật lý\n\nCần có các điều khoản để thông báo vi phạm bảo mật nội bộ và thông báo cho bất kỳ bên nào bị ảnh hưởng ra bên ngoài.\nVí dụ, Quy định bảo vệ dữ liệu chung (GDPR) tại Liên minh châu Âu đã thực hiện các quy định về thông báo vi phạm và\nhình phạt khi không tuân thủ.\n\nCác yếu tố đo lường được của HCT.01.05\n1.\nBệnh viện duy trì và kiểm tra ít nhất hàng năm một chương trình ứng phó sự cố bằng văn bản bao\ngồm các nội dung sau:\n•\nXác định tác động có thể xảy ra của một cuộc tấn công mạng vào hệ thống dữ liệu đối với mọi khía\ncạnh của việc chăm sóc và hoạt động (Xem thêm HCT.01.04, ME 1)\n•\nXác định các chiến lược để cung cấp dịch vụ và chăm sóc an toàn và chất lượng cao liên tục\n2.\nChương trình xác định các chiến lược truyền thông nội bộ và bên ngoài cho những người bị ảnh\nhưởng bởi các cuộc tấn công mạng hoặc sự kiện.\n3.\nBệnh viện triển khai các chiến thuật phục hồi và quy trình sao lưu dữ liệu liên tục để phục hồi và\nduy trì dữ liệu, đảm bảo tính toàn vẹn, tính bảo mật và an ninh của dữ liệu\n\nQuản lý các thiết bị bức xạ quang học, phẫu\nthuật điện và laser","m":[],"sec":"Công nghệ thông tin trong chăm sóc sức khỏe"},{"c":"HCT.02.00","ch":"HCT","t":"Bệnh viện thiết lập và triển khai chương trình sử dụng an toàn các thiết bị laser, phẫu thuật điện và các thiết bị bức xạ quang học khác được sử dụng để thực hiện các thủ thuật và phương pháp điều trị.","p":"Hầu như tất cả các thiết bị laser, phẫu thuật điện và các thiết bị bức xạ quang học khác được sử dụng trong môi\ntrường lâm sàng đều có khả năng gây nguy hiểm cho bệnh nhân và nhân viên nếu các quy trình và hướng dẫn an\ntoàn không được thiết lập và tuân thủ.\n\nLaser là nguồn bức xạ quang học, bao gồm bức xạ cực tím, ánh sáng khả kiến cường độ cao và bức xạ hồng ngoại.\nChùm ánh sáng cường độ cao hẹp từ laser có thể được nhắm mục tiêu và tập trung để thực hiện các thủ thuật\nphẫu thuật chính xác. Khi công nghệ phát triển, việc sử dụng laser ngày càng phổ biến hơn trong các thủ thuật\nphẫu thuật và ứng dụng lâm sàng của chúng cũng ngày càng mở rộng.\n\nPhẫu thuật laser thường ít xâm lấn, mất ít máu hơn so với phẫu thuật thông thường và bệnh nhân thường có thời\ngian phục hồi ngắn hơn. Laser cũng được sử dụng trong các thủ thuật không xâm lấn, cung cấp các phương pháp\nthay thế an toàn hơn để điều trị các tình trạng bệnh mà không cần can thiệp phẫu thuật.\n\nLaser và các thiết bị bức xạ quang học khác có thể tạo ra các nồng độ nhiệt, ánh sáng và ánh sáng phản xạ mạnh.\nKhi da và mắt tiếp xúc với nhiệt và ánh sáng mà không được bảo vệ đầy đủ, có thể xảy ra bỏng da và chấn thương\nmắt, chẳng hạn như bỏng võng mạc, đục thủy tinh thể và thoái hóa điểm vàng. Chấn thương có thể xảy ra do tiếp\nxúc trực tiếp với ánh sáng hoặc với ánh sáng phản chiếu từ tia laser.\n\nCác luồng khói là một mối nguy hiểm tiềm tàng khác. Đây là hơi, khói và các hạt được tạo ra trong một số quy\ntrình phẫu thuật. Các luồng khói do tia laser và các thiết bị phẫu thuật điện tạo ra (ví dụ, các đơn vị đốt điện) gây ra\nmối nguy hiểm tiềm tàng về hô hấp cho bệnh nhân và nhân viên, vì chúng có thể chứa các chất gây kích ứng, độc\ntố, mô, vi khuẩn, vi-rút, các mảnh máu và các hạt khác, tùy thuộc vào loại quy trình.\n\n(hC )\n\nĐể ngăn ngừa những mối nguy hiểm này và giải quyết các rủi ro về an toàn cho bệnh nhân và nhân\nviên, bệnh viện thiết lập và triển khai một chương trình sử dụng an toàn laser, phẫu thuật điện và các\nthiết bị bức xạ quang học khác bằng cách sử dụng các tiêu chuẩn của ngành và các hướng dẫn chuyên\nmôn. Chương trình tuân thủ luật pháp và quy định và bao gồm những nội dung sau:\n•\nMột cá nhân đủ tiêu chuẩn có quyền giám sát và quản lý chương trình an toàn bức xạ laser, phẫu\nthuật điện và quang\n•\nĐào tạo về các quy trình và thủ tục an toàn cho tất cả nhân viên tham gia sử dụng laser\n•\nphẫu thuật điện và các thiết bị bức xạ quang học khác\n•\nGiáo dục và đào tạo liên tục được cung cấp cho các quy trình, thực hành, thiết bị và thiết bị\nmới.\n•\nTài liệu đào tạo và giáo dục liên tục\n•\nKiểm soát hành chính và kỹ thuật để thúc đẩy an toàn và ngăn ngừa thương tích\n•\nCó sẵn thiết bị bảo vệ cá nhân cho nhân viên và bệnh nhân phù hợp với loại laser,\n•\nthiết bị phẫu thuật điện hoặc thiết bị bức xạ quang học khác đang được sử dụng hoặc loại thủ\nthuật được thực hiện trong\n•\nbệnh viện (ví dụ: kính bảo hộ, tấm chắn giác mạc, khẩu trang, găng tay và/hoặc áo choàng nếu\ncó)\n•\nChương trình bảo trì cho laser, thiết bị phẫu thuật điện và thiết bị bức xạ quang học khác và\nquy trình\n•\nđể kiểm tra hiệu suất thường xuyên như hiệu chuẩn và căn chỉnh\n•\nPhối hợp với chương trình quản lý cơ sở và phòng ngừa và kiểm soát nhiễm trùng; tất cả các sự\nkiện an toàn và kiểm soát nhiễm trùng của cơ sở đều cần được báo cáo.\n•\nPhát hiện và báo cáo các tác động xấu đến sức khỏe, xác định và thực hiện các cải tiến để\n•\nngăn ngừa tái phát\n\nCác can thiệp phẫu thuật bằng laser bao gồm:\n•\nPhẫu thuật LASIK và đục thủy tinh thể\n•\nLoại bỏ các tổn thương da\n•\nĐiều trị giãn tĩnh mạch\n•\nCác thủ thuật nha khoa để loại bỏ sâu răng hoặc tạo lại đường viền mô mềm\n\nCác phương pháp điều trị bằng bức xạ quang học không xâm lấn có thể bao gồm:\n•\nLiệu pháp ánh sáng xung cường độ cao để điều trị các tình trạng da\n•\nBức xạ cực tím để điều trị bệnh vẩy nến\n•\nTia laser để làm trắng răng\n•\nÁnh sáng khả kiến cường độ cao cho các thủ thuật nha khoa\n•\nLiệu pháp ánh sáng để điều trị đau và viêm\n•\nBức xạ hồng ngoại để điều trị căng cơ và mô mềm\n\nCác tác dụng phụ do sử dụng tia laser, phẫu thuật điện và các thiết bị bức xạ quang học khác được\nbáo cáo và các kế hoạch hành động để ngăn ngừa tái phát được thực hiện và giám sát. Các biện pháp\nkiểm soát được sử dụng để thúc đẩy an toàn và ngăn ngừa thương tích được thực hiện. Ví dụ bao\ngồm những điều sau:\n•\nTiêu chí và quy trình cho phép nhân viên vào và/hoặc làm việc trong các khu vực (vùng nguy\nhiểm) nơi sử dụng tia laser và các bức xạ quang học khác\n•\nBệnh viện xác định bất kỳ nhân viên bổ sung nào có thể cần tiếp cận các vùng nguy hiểm.\n•\nBiển báo cảnh báo được đặt bên ngoài khu vực thủ thuật để cảnh báo nhân viên, bệnh nhân, gia\nđình và khách thăm khi một phương pháp điều trị hoặc thủ thuật đang được thực hiện\n•\nThông gió thích hợp và thoát khói để giúp quản lý các luồng khói\n•\nSử dụng các dụng cụ không phản chiếu để tránh tiếp xúc với ánh sáng phản chiếu\n•\nSử dụng rèm và các rào cản khác để ngăn nhân viên, bệnh nhân, gia đình và khách thăm vô tình\ntiếp xúc với ánh sáng trực tiếp hoặc phản chiếu\n\n(hC )\n\nCác yếu tố đo lường được của HCT.02.00\n1.\nChương trình được viết của bệnh viện về việc sử dụng an toàn các thiết bị laser, phẫu thuật điện và các thiết bị\nbức xạ quang học khác đáp ứng các tiêu chí sau:\n•\nDựa trên các tiêu chuẩn của ngành và hướng dẫn chuyên môn và tuân thủ các luật và quy định hiện hành.\n•\nLà một phần của cơ cấu quản lý và an toàn cơ sở của bệnh viện.\n•\nCung cấp báo cáo ít nhất hàng năm và khi xảy ra bất kỳ sự cố an toàn nào. (Xem thêm FMS.03.00, ME 1)\n2.\nMột cá nhân đủ điều kiện với đào tạo và kinh nghiệm phù hợp sẽ giám sát và quản lý chương trình an toàn laser,\nphẫu thuật điện và bức xạ quang học.\n3.\nTất cả nhân viên tham gia sử dụng laser, phẫu thuật điện và các thiết bị bức xạ quang học khác đều được đào tạo\nvề an toàn và giáo dục liên tục; đào tạo và giáo dục liên tục được ghi chép lại.\n4.\nBệnh viện thiết lập và triển khai các biện pháp kiểm soát hành chính và kỹ thuật cho chương trình an toàn laser,\nphẫu thuật điện và bức xạ quang học để thúc đẩy an toàn và ngăn ngừa thương tích cho bệnh nhân và nhân viên.\n5.\nCó sẵn thiết bị bảo vệ cá nhân phù hợp với loại laser, phẫu thuật điện và các thiết bị bức xạ quang học khác và\nloại thủ thuật cho nhân viên và bệnh nhân, và nhân viên sử dụng đúng cách và đảm bảo bệnh nhân và nhân viên\nđược bảo vệ trong quá trình thực hiện thủ thuật.\n6.\nBệnh viện có các quy trình kiểm tra, thử nghiệm và bảo trì laser, phẫu thuật điện và các thiết bị bức xạ quang học\nkhác, bao gồm kiểm tra hiệu chuẩn và căn chỉnh laser thường xuyên, và các hoạt động này được thực hiện bởi\nnhững cá nhân có trình độ và được đào tạo.\n\nQuản lý thông\n\nTổng quan\nCung cấp dịch vụ chăm sóc bệnh nhân là một nỗ lực phức tạp phụ thuộc rất nhiều vào truyền thông thông tin.\nTruyền thông này là với và với bệnh nhân và gia đình của họ, các bác sĩ chăm sóc sức khỏe khác và cộng đồng.\nNhững thất bại trong truyền thông là một trong những nguyên nhân gốc rễ phổ biến nhất gây ra các sự cố về an toàn\ncho bệnh nhân. Thông thường, những thất bại trong truyền thông này là do chữ viết tay không rõ ràng và việc sử dụng\nkhông thống nhất hoặc không chuẩn hóa các chữ viết tắt, ký hiệu và mã trong toàn bộ tổ chức. Một phần không thể\nthiếu của quản lý thông tin trong chăm sóc sức khỏe là theo dõi và bảo vệ việc sử dụng thông tin của bệnh nhân. Để\ncung cấp, phối hợp và tích hợp các dịch vụ, các tổ chức chăm sóc sức khỏe dựa vào thông tin về khoa học chăm sóc,\ntừng bệnh nhân, dịch vụ chăm sóc được cung cấp, kết quả chăm sóc và hiệu suất của chính họ. Giống như nguồn\nnhân lực, vật lực và tài chính, thông tin là một nguồn lực mà các nhà lãnh đạo bệnh viện phải quản lý hiệu quả. Mọi\nbệnh viện đều tìm cách thu thập, quản lý và sử dụng thông tin để cải thiện kết quả của bệnh nhân và hiệu suất của tổ\nchức nói chung và cá nhân.\nTheo thời gian, các bệnh viện trở nên hiệu quả hơn trong các lĩnh vực sau:\n•\nXác định nhu cầu về thông tin và công nghệ thông tin\n•\nThiết kế hoặc triển khai các hệ thống quản lý thông tin\n•\nXác định và thu thập dữ liệu và thông tin\n•\nPhân tích dữ liệu và chuyển đổi dữ liệu thành thông tin\n•\nTruyền và báo cáo dữ liệu và thông tin\n•\nBảo vệ tính bảo mật, an ninh và toàn vẹn của dữ liệu và thông tin\n•\nTích hợp và sử dụng thông tin để cải thiện hiệu suất\nMặc dù máy tính hóa và các công nghệ khác cải thiện hiệu quả, các nguyên tắc quản lý công nghệ thông tin tốt được\náp dụng cho tất cả các phương pháp lập tài liệu. Các tiêu chuẩn này được thiết kế để tương thích như nhau với các hệ\nthống không được vi tính hóa và các công nghệ hiện tại/tương lai.\n\nTiêu chuẩn\nSau đây là danh sách tất cả các tiêu chuẩn cho chức năng này. Chúng được trình bày ở đây để thuận tiện cho bạn mà\nkhông có các tuyên bố ý định hoặc các yếu tố có thể đo lường. Để biết thêm thông tin về các tiêu chuẩn này, vui lòng\nxem phần tiếp theo trong chương này, Tiêu chuẩn, Ý định và","m":[],"sec":"Quản lý các thiết bị bức xạ quang học, phẫu thuật điện và laser"},{"c":"HRP.01.00","ch":"HRP","t":"Lãnh đạo bệnh viện chịu trách nhiệm bảo vệ các đối tượng nghiên cứu của con người.","p":"Các nhà lãnh đạo bệnh viện nhận ra trách nhiệm của mình trong việc bảo vệ quyền của đối tượng nghiên cứu là\ncon người và cam kết thúc đẩy một môi trường an toàn cho những bệnh nhân này.\n\nNghiên cứu đối tượng nghiên cứu là một nỗ lực phức tạp và quan trọng đối với một bệnh viện. Cam kết của các\nnhà lãnh đạo khoa/dịch vụ đối với nghiên cứu đối tượng nghiên cứu là con người không tách biệt với cam kết của\nhọ đối với việc chăm sóc bệnh nhân—cam kết được tích hợp ở mọi cấp độ. Các nhà lãnh đạo bệnh viện nhận ra\nmức độ cam kết và sự tham gia cá nhân cần thiết để thúc đẩy nghiên cứu khoa học. Do đó, các cân nhắc về đạo\nđức, giao tiếp tốt, các nhà lãnh đạo khoa và dịch vụ có trách nhiệm, tuân thủ quy định và các nguồn lực tài chính và\nphi tài chính là các thành phần của cam kết này. Với các quy định khác nhau của địa phương, các nhà lãnh đạo bệnh\nviện phải bảo vệ bệnh nhân và tôn trọng quyền của họ trong quá trình nghiên cứu, điều tra và thử nghiệm lâm sàng.\n\nBảo vệ quyền của đối tượng nghiên cứu là con người và thúc đẩy một môi trường an toàn cho những bệnh nhân\nnày đòi hỏi các bệnh viện phải có hiểu biết và tuân thủ các nguồn quy định và tiêu chuẩn chuyên môn dành riêng\ncho nghiên cứu lâm sàng, chẳng hạn như các tiêu chuẩn từ Hội nghị quốc tế về điều hòa (ICH)/Tổ chức Y tế Thế\ngiới (WHO) Thực hành lâm sàng tốt (GCP).\n\nCác yếu tố đo lường được của HRP.01.00\n1.\nLãnh đạo bệnh viện thiết lập và thúc đẩy một bộ quy tắc ứng xử đạo đức nghề nghiệp.\n2.\nD Lãnh đạo bệnh viện, bằng lời nói và văn bản, truyền đạt trong bệnh viện cam kết bảo vệ những người\ntham gia nghiên cứu là con người và ủng hộ bộ quy tắc ứng xử đạo đức nghề nghiệp.\n3.\nLãnh đạo bệnh viện chịu trách nhiệm bảo vệ bệnh nhân bất kể nhà tài trợ của nghiên cứu là ai.\n4.\nD Lãnh đạo bệnh viện có quy trình lập ngân sách để cung cấp đủ nguồn lực cho hoạt động hiệu quả của\nchương trình nghiên cứu.","m":[]},{"c":"HRP.01.01","ch":"HRP","t":"Lãnh đạo bệnh viện thiết lập phạm vi của chương trình nghiên cứu.","p":"Để đảm bảo kiểm soát và nguồn lực đầy đủ hỗ trợ cho mọi nghiên cứu trong bệnh viện, các nhà lãnh đạo\nbệnh viện phải đưa ra quyết định liên quan đến phạm vi hoạt động nghiên cứu, bao gồm các loại hình và địa\nđiểm. Nghiên cứu y khoa được tiến hành tại bệnh viện đại diện cho nhiều lĩnh vực y khoa và/hoặc chuyên\nkhoa khác nhau trong tổ chức và bao gồm nghiên cứu cơ bản, lâm sàng và dịch vụ y tế. Nghiên cứu như vậy\ncó thể bao gồm các thử nghiệm lâm sàng, can thiệp điều trị, phát triển công nghệ y khoa mới và nghiên cứu\nkết quả, trong số những nghiên cứu khác. Các nhà lãnh đạo phải đặt ra các thông số về thời điểm một nhân\nviên của bệnh viện có thể tham gia với tư cách là đối tượng nghiên cứu. Ngoài ra, các nhà lãnh đạo có trách\nnhiệm đảm bảo rằng có đủ số lượng nhân viên được đào tạo để làm nghiên cứu viên chính và các thành viên\nkhác của nhóm nghiên cứu. Tài liệu về trình độ chuyên môn bắt buộc của nhân viên phải bao gồm các thông\nsố này.\n\nCác yếu tố đo lường được của HRP.01.01\n1. D Lãnh đạo bệnh viện xác định phạm vi của chương trình nghiên cứu.\n2. Lãnh đạo bệnh viện xác định các cơ sở và nguồn lực hỗ trợ chương trình nghiên cứu.\n3. Lãnh đạo bệnh viện xác định trình độ của nhân viên được phép tham gia chương trình nghiên cứu với\ntư cách là nhà nghiên cứu chính hoặc các thành viên khác của nhóm nghiên cứu.\n4. D Có tài liệu về trình độ của nhân viên được phép tham gia chương trình nghiên cứu.\n5. Lãnh đạo bệnh viện xác định những trường hợp mà nhân viên và nhân viên bệnh viện có thể làm đối\ntượng nghiên cứu.","m":[]},{"c":"HRP.01.02","ch":"HRP","t":"Lãnh đạo bệnh viện thiết lập chính sách cho các nhà tài trợ nghiên cứu để đảm bảo cam kết của họ đối với việc tiến hành nghiên cứu có đạo đức.","p":"Lãnh đạo và nhà tài trợ bệnh viện chịu trách nhiệm về mọi yếu tố của nghiên cứu cụ thể, do đó, việc thiết lập kỳ\nvọng và trách nhiệm rõ ràng đảm bảo hiểu được cam kết về nghiên cứu có đạo đức. Lãnh đạo và nhà tài trợ bệnh\nviện phải chia sẻ trách nhiệm trong việc đảm bảo an toàn cho đối tượng nghiên cứu và bảo vệ quyền của họ. Các\nchính sách, quy trình và thỏa thuận hợp đồng do bệnh viện và nhà tài trợ thiết lập và thực hiện phải phản ánh cam\nkết bảo vệ quyền của đối tượng nghiên cứu, các hoạt động nghiên cứu an toàn và có đạo đức, các sáng kiến tập\ntrung vào chất lượng và tuân thủ luật pháp và quy định. Các giao thức nghiên cứu phải phản ánh rằng các nhà tài\ntrợ đáp ứng mọi yêu cầu và lãnh đạo bệnh viện xác minh điều này. Trách nhiệm của nhà tài trợ nghiên cứu bao\ngồm khởi xướng, quản lý và cam kết tài chính cho một thử nghiệm lâm sàng, ngoài việc đảm bảo rằng nghiên cứu\nđược tiến hành theo các chính sách và giao thức, luật pháp và quy định và hướng dẫn hiện hành. Nhà tài trợ nghiên\ncứu phải đủ điều kiện cho vai trò này. Các điều kiện của nhà tài trợ nghiên cứu có thể bao gồm đào tạo về nhà tài\ntrợ, nhà nghiên cứu và/hoặc thực hành lâm sàng tốt (GCP); và lý lịch, chứng chỉ hoặc đào tạo về nghiên cứu lâm\nsàng và chuẩn bị đề xuất.\n\nCác yếu tố đo lường được của HRP.01.02\n1. D Lãnh đạo bệnh viện thiết lập chính sách bằng văn bản cho các nhà tài trợ nghiên cứu với các yêu cầu\nvề trách nhiệm giải trình đối với nghiên cứu, bao gồm các nội dung sau:\n•\nTuân thủ các chính sách và quy trình của bệnh viện để theo dõi và đánh giá chất lượng, sự an toàn và\nđạo đức của nghiên cứu (Xem thêm GLD.07.00, ME 1)\n•\nCác nhóm nghiên cứu phải được đào tạo và có trình độ để tiến hành nghiên cứu.\n•\nQuy trình bảo vệ quyền riêng tư và tính bảo mật của dữ liệu đối tượng\n•\nQuy trình đảm bảo dữ liệu nghiên cứu đáng tin cậy và hợp lệ, đồng thời kết quả và báo cáo chính\nxác về mặt thống kê, có đạo đức và khách quan\n•\nCác ưu đãi cho bệnh nhân hoặc nhà nghiên cứu không được làm ảnh hưởng đến tính toàn vẹn của\nnghiên cứu.\n2. Lãnh đạo bệnh viện xác minh rằng nhà tài trợ của một giao thức nghiên cứu phải có trình độ chuyên\nmôn cho vai trò này.\n3. D Có tài liệu xác nhận rằng nhà tài trợ hiểu rõ trách nhiệm và trách nhiệm giải trình của họ đối với\nnghiên cứu.","m":[]},{"c":"HRP.01.03","ch":"HRP","t":"Khi một hoặc nhiều nhiệm vụ và chức năng liên quan đến nghiên cứu của nhà tài trợ được cung cấp thông qua một tổ chức nghiên cứu hợp đồng thương mại hoặc học thuật bên ngoài, trách nhiệm của tổ chức nghiên cứu hợp đồng bên ngoài được xác định rõ ràng.","p":"Nhà tài trợ chịu trách nhiệm lựa chọn cẩn thận một tổ chức nghiên cứu theo hợp đồng, phân định rõ ràng trách nhiệm\ngiải trình và giám sát việc tuân thủ theo hợp đồng. Khi các quy định liên quan đến nhiệm vụ được nhà tài trợ chuyển\ngiao cho tổ chức nghiên cứu theo hợp đồng, nhà tài trợ giám sát việc tuân thủ các quy định đó như một phần của quá\ntrình xem xét hợp đồng. Bệnh viện chấp thuận hợp đồng được đề xuất với tổ chức nghiên cứu theo hợp đồng do nhà\ntài trợ lựa chọn.\n\nNghiên cứu đối tượng là con người có nhiều thành phần, một số trong đó nhà tài trợ có thể chọn ký hợp đồng với một\ncá nhân hoặc tổ chức bên ngoài, thường được gọi là tổ chức nghiên cứu theo hợp đồng. Các thành phần đó có thể bao\ngồm tuyển dụng đối tượng, tiến hành nghiên cứu, cung cấp quản lý dữ liệu hoặc đóng vai trò là cơ chế xem xét nghiên\ncứu.\n\nCác yếu tố đo lường được của HRP.01.03\n1.\nD Bệnh viện thiết lập và thực hiện một quy trình bằng văn bản để xác định các hoạt động và trách nhiệm của\nmột tổ chức nghiên cứu theo hợp đồng.\n2.\nD Các nhiệm vụ và chức năng được nhà tài trợ chuyển giao cho tổ chức nghiên cứu theo hợp đồng được nêu\ntrong một hợp đồng bằng văn bản.\n3.\nD Hợp đồng nêu rõ rằng tổ chức nghiên cứu theo hợp đồng hoặc nhà tài trợ có trách nhiệm giám sát và đánh giá\nchất lượng, sự an toàn và đạo đức của nghiên cứu. (Xem thêm GLD.07.00, ME 1)\n4.\nNhà tài trợ có trách nhiệm giám sát hợp đồng.","m":[]},{"c":"HRP.01.04","ch":"HRP","t":"Các nhà lãnh đạo bệnh viện thực hiện một quy trình để cung cấp đánh giá ban đầu và liên tục về tất cả các nghiên cứu trên đối tượng là con người.","p":"Một trong những quy trình quan trọng nhất liên quan đến nghiên cứu đối tượng là quá trình xem xét và giám\nsát của một nhóm cá nhân độc lập, thường được gọi là Hội đồng Đánh giá Thể chế (IRB), ủy ban đạo đức\nhoặc danh nghĩa tương tự giám sát mọi khía cạnh của giao thức nghiên cứu để đảm bảo bảo vệ bệnh nhân và\nnghiên cứu an toàn. Thành phần, phạm vi trách nhiệm và các yếu tố khác có thể được mô tả trong luật hoặc\nquy định.\n\nQuy trình đánh giá nghiên cứu có thể được giao cho một tổ chức bên ngoài như IRB khu vực hoặc quốc gia. Các chính\nsách, thủ tục và cấu trúc của quy trình đánh giá nghiên cứu được chỉ định bởi các nhà lãnh đạo bệnh viện, cũng như các\nchức năng nào có thể hoặc không thể được chuyển giao cho một tổ chức nghiên cứu theo hợp đồng. Ngoài ra, các nhà lãnh\nđạo bệnh viện có trách nhiệm xác định các loại nghiên cứu được miễn khỏi chức năng đánh giá này và ghi chép lại các hoạt\nđộng của nhóm đánh giá. Việc ghi chép lại quy trình này là một thành phần quan trọng trong trách nhiệm của các nhà lãnh\nđạo trong việc đánh giá, ít nhất là hàng năm, và xác định quy trình đánh giá nghiên cứu đang hoạt động tốt như thế nào.\n\nCác yếu tố đo lường được của HRP.01.04\n1.\nLãnh đạo bệnh viện xác định và hỗ trợ cấu trúc và các yêu cầu hoạt động của quy trình đánh giá nghiên cứu.\n2.\nQuy trình đánh giá nghiên cứu tuân thủ các luật và quy định hiện hành.\n3.\nLãnh đạo bệnh viện chỉ định các yêu cầu của các tổ chức bên ngoài bệnh viện cung cấp toàn bộ hoặc một\nphần quy trình đánh giá nghiên cứu, chẳng hạn như tổ chức nghiên cứu theo hợp đồng.\n4.\nLãnh đạo bệnh viện đảm bảo rằng nghiên cứu được miễn quy trình đánh giá nghiên cứu được xác định.\n5.\nD Lãnh đạo bệnh viện chỉ định các yêu cầu về tài liệu về các hoạt động của quy trình đánh giá nghiên cứu.\n6.\nD Lãnh đạo bệnh viện cung cấp để đánh giá tất cả các quy trình đánh giá nghiên cứu ít nhất hàng năm.\n\nChương trình an toàn","m":[]},{"c":"HRP.02.00","ch":"HRP","t":"Bệnh viện quản lý xung đột lợi ích với nghiên cứu được tiến hành tại bệnh viện.","p":"Xung đột lợi ích có thể phát sinh từ nhiều nguồn và dưới nhiều hình thức đối với những người tài trợ hoặc\ntham gia nghiên cứu trên đối tượng là con người. Xung đột có thể là về mặt tài chính (như thanh toán cho\nviệc tuyển dụng một số loại đối tượng nhất định) hoặc phi tài chính (như các chuyến đi để diễn thuyết tại\ncác hội nghị). Quy trình đánh giá nghiên cứu có thể xác định và giảm thiểu các xung đột như vậy hoặc bệnh\nviện có thể sử dụng hoặc phát triển một loại cơ chế khác để giám sát và giảm thiểu xung đột. Cơ chế này\nbao gồm giáo dục về những gì cấu thành nên xung đột và cách quản lý xung đột thành công.\n\nCác yếu tố đo lường được của HRP.02.00\n1. D Bệnh viện có chính sách bằng văn bản để xác định và quản lý xung đột lợi ích với nghiên cứu được\ntiến hành tại bệnh viện.\n2. D Chính sách xung đột lợi ích của bệnh viện bao gồm một quy trình quản lý xung đột lợi ích, cả về tài\nchính và phi tài chính.\n3. Bệnh viện chỉ định những cá nhân, ủy ban và những người khác mà các yêu cầu áp dụng.\n4. Bệnh viện có quy trình giáo dục và giám sát liên tục để đảm bảo tuân thủ các yêu cầu.","m":[]},{"c":"HRP.02.01","ch":"HRP","t":"Bệnh viện tích hợp chương trình nghiên cứu đối tượng con người vào chương trình chất lượng và an toàn bệnh nhân của bệnh viện. 333 Human Subjects Research Programs (HRP) Ủy ban chung Quốc tế aCCreditation standards for Hospitals, 8tH edition.","p":"Báo cáo các sự kiện liên quan đến các giao thức nghiên cứu có thể cung cấp thông tin quan trọng để hiểu được\nchất lượng và sự an toàn chung của việc chăm sóc bệnh nhân tại bệnh viện. Ví dụ, một sự kiện bất lợi đáng kể\nkhi một loại thuốc được sử dụng cho mục đích không theo chỉ định là thông tin an toàn quan trọng cho bệnh\nnhân, cần phải là một phần của quy trình theo dõi thuốc đang diễn ra của bệnh viện.\nNghiên cứu đối tượng nghiên cứu là con người có thể liên quan đến các loại thủ thuật phẫu thuật mới, việc sử\ndụng dược phẩm mới hoặc việc sử dụng không theo chỉ định của các loại thuốc hiện có trong công thức, việc sử\ndụng các phương thức điều trị cho người lớn trên nhóm trẻ em và nhiều chủ đề và phương pháp nghiên cứu\nkhác. Điều quan trọng hàng đầu là đưa các hoạt động nghiên cứu vào các quy trình thường quy của bệnh viện; ví\ndụ, quy trình đặt hàng, phân phối và quản lý thuốc đang được nghiên cứu. Các quy trình thường quy cũng bao\ngồm việc báo cáo các sự kiện bất lợi thông qua các quy trình theo dõi chất lượng và an toàn cho bệnh nhân. Do\nđó, việc báo cáo một sự kiện bất lợi liên quan đến bệnh nhân trong bệnh viện theo giao thức nghiên cứu phải\nđược thực hiện với cơ chế theo dõi chất lượng của bệnh viện cũng như với nhà tài trợ của nghiên cứu hoặc tổ\nchức nghiên cứu theo hợp đồng.\nTất cả các yếu tố của chương trình nghiên cứu đối tượng nghiên cứu là con người cần được đánh giá để xác định\nchương trình chất lượng và an toàn nào của bệnh viện có thể áp dụng. Hơn nữa, bất kỳ quy trình báo cáo và giám\nsát nào đang diễn ra trong bệnh viện đều phải được đưa vào chương trình nghiên cứu. Ví dụ bao gồm:\n•\nXử lý và thải bỏ một số dược phẩm nghiên cứu thử nghiệm, đây phải là một thành phần của việc quản lý\nvật liệu nguy hiểm\n•\nGiám sát và bảo dưỡng thiết bị y tế được sử dụng trong các quy trình thử nghiệm\nĐiều này cũng đúng khi một số hoạt động nghiên cứu được cung cấp bởi một tổ chức nghiên cứu theo hợp đồng.\n\nCác yếu tố đo lường được của HRP.02.01\n1. Chương trình nghiên cứu là một thành phần trong các quy trình của bệnh viện nhằm báo cáo và hành động đối\nvới các sự kiện trọng yếu và các sự kiện bất lợi khác, cũng như các quy trình để rút kinh nghiệm từ các sự cố\nsuýt xảy ra (hoặc các cuộc gọi suýt xảy ra). (Xem thêm Chính sách sự kiện trọng yếu và APR.09.00, ME 1)\n2. Chương trình nghiên cứu được đưa vào các chương trình của bệnh viện về quản lý vật liệu nguy hiểm, quản\nlý thiết bị y tế và quản lý thuốc. (Xem thêm FMS.05.00, ME 1; FMS.07.00, ME 1; MMU.01.00, ME 1)\n3. Việc đánh giá nhân viên tham gia chương trình nghiên cứu được đưa vào các quy trình giám sát liên tục về hiệu\nsuất chuyên môn. (Xem thêm SQE.01.03, ME 2)","m":[]},{"c":"HRP.02.02","ch":"HRP","t":"Bệnh viện thông báo cho bệnh nhân và gia đình về cách tiếp cận nghiên cứu lâm sàng, điều tra lâm sàng hoặc thử nghiệm lâm sàng và bao gồm các biện pháp bảo vệ cho nhóm dân số dễ bị tổn thương để giảm thiểu khả năng bị ép buộc hoặc ảnh hưởng không đúng mực.","p":"Các biện pháp bảo vệ được đưa ra thông qua chức năng đánh giá nghiên cứu của bệnh viện để bảo vệ những\nbệnh nhân dễ bị tổn thương, những người có thể có nguy cơ bị ép buộc hoặc bị ảnh hưởng không đúng mực\nkhi tham gia vào các dự án nghiên cứu. Những bệnh nhân dễ bị tổn thương bao gồm trẻ em, tù nhân, phụ nữ\nmang thai, người khuyết tật về tinh thần, người gặp bất lợi về kinh tế hoặc giáo dục và những người khác bị suy\ngiảm hoặc không có khả năng đưa ra quyết định sáng suốt hoặc tự nguyện để tham gia nghiên cứu. Một nhóm\nkhác có thể được coi là nhóm dân số dễ bị tổn thương là nhân viên bệnh viện. Nhân viên có thể cảm thấy áp lực\nkhi tham gia; ví dụ, khi nhà nghiên cứu chính là người giám sát của họ.\n\nKhi bệnh nhân quyết định tham gia nghiên cứu và đồng ý, cá nhân cung cấp thông tin và có được sự đồng ý sẽ\nđược ghi chú trong hồ sơ y tế. Đôi khi, một giao thức nghiên cứu có thể được thay đổi dựa trên những phát\nhiện ban đầu; ví dụ, liều dùng thuốc có thể được thay đổi. Sự đồng ý của bệnh nhân sẽ được lấy lại trong những\ntrường hợp này và những trường hợp tương tự.\n\nRủi ro đối với sự an toàn, quyền và sức khỏe của bệnh nhân và/hoặc gia đình, hoặc rủi ro do ép buộc hoặc\nảnh hưởng không đúng mực được báo cáo là các sự kiện bất lợi, không được lên kế hoạch. Trong những\ntrường hợp này, quy trình IRB bao gồm quy trình của bệnh viện và nhà tài trợ để ngăn ngừa rủi ro tiếp\ntheo khi thử nghiệm nghiên cứu tiếp tục.\n\nCác yếu tố đo lường được của HRP.02.02\n1.\nBệnh viện thiết lập và triển khai quy trình đồng ý có thông tin cho phép bệnh nhân đưa ra quyết định có\nthông tin và tự nguyện về việc tham gia nghiên cứu lâm sàng, điều tra lâm sàng hoặc thử nghiệm lâm sàng,\nbao gồm các nội dung sau:\n•\nCách thức xin và ghi lại sự đồng ý tham gia\n•\nTrong trường hợp nào sẽ xin lại sự đồng ý trong quá trình nghiên cứu\nLưu ý: Điều này được thực hiện thông qua quy trình đánh giá nghiên cứu.\n2.\nBệnh nhân và gia đình được xác định và thông báo về cách tiếp cận nghiên cứu lâm sàng, các cuộc điều tra\nlâm sàng hoặc thử nghiệm lâm sàng có liên quan đến nhu cầu điều trị của họ.\n3.\nThông qua quy trình đánh giá nghiên cứu, bệnh viện thực hiện các biện pháp bảo vệ để bảo vệ sự an toàn,\nquyền và phúc lợi của những bệnh nhân dễ bị tổn thương, theo xác định của bệnh viện, những người có\nthể có nguy cơ bị ép buộc hoặc bị ảnh hưởng không đúng mực. (Xem thêm PCC.01.04, ME 4)\n4.\nThông qua quy trình đánh giá nghiên cứu, bệnh viện thực hiện các biện pháp bảo vệ để bảo vệ sự an toàn,\nquyền và phúc lợi của nhân viên bệnh viện, những người có thể có nguy cơ bị ép buộc hoặc bị ảnh hưởng\nkhông đúng mực.\n\nGiáo dục chuyên\nnghiệp y tế (MPE)\n\nTổng quan\nViệc tích hợp giáo dục cho sinh viên và thực tập sinh y khoa vào hoạt động của bệnh viện cần phải phù hợp với sứ\nmệnh, kế hoạch chiến lược, phân bổ nguồn lực và chương trình chất lượng và an toàn cho bệnh nhân của bệnh viện.\nCác tiêu chuẩn MPE nhấn mạnh đến sự an toàn và chất lượng chăm sóc dành cho bệnh nhân được thực tập sinh và\nsinh viên chăm sóc như một phần trong các dịch vụ của bệnh viện. Đối với các chương trình giáo dục chuyên nghiệp,\ncả sau đại học và đại học, cơ quan quản lý và lãnh đạo của bệnh viện có trách nhiệm đảm bảo có sự giám sát phù hợp\nđối với việc chăm sóc, điều trị và các dịch vụ cho bệnh nhân được cung cấp trong mọi bối cảnh giảng dạy. Để đảm\nbảo trải nghiệm phong phú và có ý nghĩa cho sinh viên và thực tập sinh y khoa, ngoài cam kết của cơ quan quản lý và\nlãnh đạo bệnh viện, cần có nhiều yếu tố.\n\nThực tập sinh và sinh viên đáp ứng các tiêu chí sau:\n• Có định hướng về tổ chức và các phòng ban có liên quan.\n• Hiểu và tham gia vào các hoạt động cải tiến chất lượng.\n• Tích cực tham gia vào văn hóa an toàn của bệnh viện.\n\nCơ quan quản lý và lãnh đạo bệnh viện thực hiện các hoạt động sau:\n• Tạo quy trình chỉ đạo và chịu trách nhiệm của các thành viên y tế của chương trình giảng dạy bệnh viện\nvà các nhân viên liên quan khác.\n• Có hiểu biết về các chương trình giảng dạy dựa trên thông tin dữ liệu kịp thời.\n• Yêu cầu các quy trình cải tiến trong các chương trình giảng dạy liên quan đến chăm sóc bệnh nhân khi có cơ hội\ncải thiện.\n\nĐối với ngôn ngữ chuẩn trong chương này và trong chương SQE, các thuật ngữ và định nghĩa liên quan sau đây được\náp dụng:\n\nNhân viên y tế\nTất cả các bác sĩ, nha sĩ và các chuyên gia khác được cấp phép hành nghề độc lập (không có sự giám sát) và\ncung cấp các dịch vụ phòng ngừa, chữa bệnh, phục hồi, phẫu thuật, phục hồi chức năng hoặc các dịch vụ y\ntế hoặc nha khoa khác cho bệnh nhân; hoặc cung cấp các dịch vụ giải thích cho bệnh nhân, chẳng hạn như\nbệnh lý học, X-quang hoặc dịch vụ xét nghiệm. Tất cả các phân loại cuộc hẹn, tất cả các loại và cấp độ nhân\nviên (nhân viên được tuyển dụng, danh dự, hợp đồng, thăm khám và nhân viên cộng đồng tư nhân) đều\nđược bao gồm. Nhân viên thăm khám bao gồm những người là\ngiáo viên/gia sư và những người khác được phép cung cấp dịch vụ chăm sóc bệnh nhân tạm thời. Bệnh viện\nphải xác định những nhân viên lâm sàng khác, chẳng hạn như \"cán bộ nội trú\", \"bác sĩ nội trú\", \"đồng\nnghiệp\" và \"bác sĩ mới ra trường\", những người không còn được đào tạo nữa nhưng có thể hoặc không\nđược bệnh viện cho phép hành nghề độc lập.\n\nDo đó, thuật ngữ nhân viên y tế bao gồm tất cả các bác sĩ và các chuyên gia khác được phép điều trị cho bệnh\nnhân một phần hoặc toàn bộ độc lập, bất kể mối quan hệ của họ với bệnh viện (ví dụ: nhân viên được tuyển\ndụng hoặc cố vấn độc lập). Ở một số nền văn hóa, bác sĩ y học cổ truyền, bác sĩ châm cứu, bác sĩ nắn xương\nvà những người khác có thể được pháp luật và bệnh viện cho phép hành nghề độc lập. Do đó, họ được coi\nlà thành viên của đội ngũ nhân viên y tế và các tiêu chuẩn này áp dụng đầy đủ.\n\nTiêu chuẩn\nSau đây là danh sách tất cả các tiêu chuẩn cho chức năng này. Chúng được trình bày ở đây để thuận tiện cho bạn mà\nkhông có các tuyên bố ý định hoặc các yếu tố có thể đo lường. Để biết thêm thông tin về các tiêu chuẩn này, vui lòng\nxem phần tiếp theo trong chương này, Tiêu chuẩn, Ý định và","m":[]},{"c":"IPSG.01.00","ch":"IPSG","t":"Bệnh viện triển khai quy trình nâng cao độ chính xác trong việc nhận dạng bệnh nhân.","p":"Việc nhận dạng bệnh nhân không chính xác có thể dẫn đến sai sót về người và sai quy trình, sai sót về điều trị,\nsai sót về thuốc, sai sót về chẩn đoán, v.v. có thể gây hại cho bệnh nhân. Việc nhận dạng chính xác bệnh nhân và\nkết hợp họ với phương pháp điều trị và dịch vụ dự định phải được thực hiện trong mọi bối cảnh chăm sóc.\nQuy trình nhận dạng được sử dụng trong toàn bệnh viện yêu cầu hai mã định danh bệnh nhân, chẳng hạn như\ntên bệnh nhân, số định danh, ngày sinh, vòng đeo tay có mã vạch hoặc các cách khác. Không thể sử dụng số\nphòng hoặc vị trí của bệnh nhân trong bệnh viện hoặc các số khác như số lồng ấp cho trẻ sơ sinh để nhận dạng.\nHai mã định danh bệnh nhân khác nhau được sử dụng có thể khác nhau trong các trường hợp khác nhau; tuy\nnhiên, hai mã định danh được sử dụng phải nhất quán trong một khu vực. Thực hành tốt nhất là bệnh nhân\nphải tham gia vào quy trình nhận dạng ở bất kỳ mức độ nào có thể. Có những trường hợp đặc biệt mà bệnh\nviện có thể cần phát triển một quy trình cụ thể để nhận dạng bệnh nhân. Quy trình này xem xét các nhu cầu\nriêng biệt của bệnh nhân và nhân viên sử dụng quy trình để nhận dạng bệnh nhân trong những trường hợp đặc\nbiệt này để ngăn ngừa sai sót. Cần có hai mã định danh bệnh nhân khác nhau trong bất kỳ trường hợp nào liên\nquan đến can thiệp của bệnh nhân. Bệnh nhân được xác định trước khi cung cấp phương pháp điều trị, trước\nkhi thực hiện các thủ thuật và trước khi thực hiện bất kỳ thủ thuật chẩn đoán nào. Bệnh viện nên đưa những\nđiều sau vào các hoạt động xác định bệnh nhân của mình:\n•\nCho bệnh nhân tham gia vào quá trình xác định bất cứ khi nào có thể.\n•\nBao gồm các trường hợp đặc biệt trong quá trình xác định. Ví dụ bao gồm những trường hợp sau:\no Bệnh nhân hôn mê hoặc lú lẫn/mất phương hướng không có thông tin nhận dạng\no Bệnh nhân mới sinh khi cha mẹ chưa chọn tên ngay, chẳng hạn như sử dụng tên của mẹ ngoài \"bé\ntrai\" hoặc \"bé gái\" và họ của cha mẹ (ví dụ: \"Bé gái Mariam Khan\" thay vì \"Bé gái Khan\" hoặc \"Bé trai\nMaria Silva\" thay vì \"Bé trai Silva\" trong trường hợp có nhiều hơn một em bé cùng giới tính có cùng họ\nvà thêm tên thứ ba như tên của cha hoặc tên đệm của mẹ nếu có khả năng có hai hoặc nhiều bệnh\nnhân trong khoa có cùng tên và họ hoặc sinh nhiều con\n•\nCác tổ chức cho phép sử dụng các mã định danh khác nhau trong các khu vực hoặc tình huống chăm sóc\nkhác nhau phải đảm bảo rằng quy trình này nhất quán trong những trường hợp này, như trong các ví dụ\nsau:\no Tên và ngày sinh của bệnh nhân được sử dụng trong các tương tác bằng lời nói với bệnh nhân trong\nkhoa; hai mã định danh giống nhau này phải được sử dụng trong tất cả các tương tác bằng lời nói với\nbệnh nhân.\no Tên và số nhận dạng hoặc số hồ sơ y tế của bệnh nhân được sử dụng trong thời gian chờ phẫu\nthuật/xâm lấn, để dán nhãn mẫu vật hoặc để báo cáo các xét nghiệm chẩn đoán, v.v.;\nhai mã định danh này phải được sử dụng trong mọi trường hợp tương tự.\n•\nBệnh nhân được xác định trước khi cung cấp phương pháp điều trị, trước khi thực hiện các thủ thuật,\ntrước bất kỳ thủ thuật chẩn đoán nào và trước bất kỳ phương pháp điều trị, chăm sóc hoặc can thiệp nào\nkhác dành cho một bệnh nhân cụ thể; điều này bao gồm việc dán nhãn bất kỳ phương pháp điều trị và\nthuốc nào dành cho một bệnh nhân cụ thể. Các ví dụ bao gồm:\no  Mẫu máu và mẫu bệnh lý\n\no  Khay đựng đồ ăn\no  Sữa mẹ vắt ra\n\nCác yếu tố đo lường được của IPSG.01.00\n1.\nBệnh viện sử dụng ít nhất hai mã định danh bệnh nhân, không bao gồm việc sử dụng số phòng hoặc vị\ntrí của bệnh nhân trong bệnh viện, để nhận dạng bệnh nhân và dán nhãn các yếu tố liên quan đến kế\nhoạch chăm sóc và điều trị của bệnh nhân. (Xem thêm MMU.04.01, ME 4; MMU.05.03, ME 4;\nMOI.03.00, ME 1)\n2. Bệnh viện xác định bệnh nhân bằng ít nhất hai mã định danh trước khi thực hiện các thủ thuật chẩn đoán,\ncung cấp phương pháp điều trị và thực hiện các thủ thuật khác. (Xem thêm MMU.04.01, ME 4)\n3. Bệnh viện đảm bảo nhận dạng chính xác bệnh nhân trong những trường hợp đặc biệt, chẳng hạn\nnhư bệnh nhân hôn mê hoặc trẻ sơ sinh chưa được đặt tên ngay lập tức.\n\nMục tiêu 2: Cải thiện giao tiếp hiệu quả","m":[],"sec":"Mục tiêu 1: Xác định đúng bệnh nhân"},{"c":"IPSG.02.00","ch":"IPSG","t":"Bệnh viện thực hiện quy trình báo cáo kết quả quan trọng của các xét nghiệm chẩn đoán.","p":"Bệnh nhân có thể bị tổn hại khi kết quả quan trọng của các xét nghiệm chẩn đoán không được báo cáo và xử lý kịp\nthời. Kết quả quan trọng được định nghĩa là sự sai lệch so với phạm vi bình thường, biểu thị trạng thái bệnh lý sinh lý\ncó nguy cơ cao hoặc đe dọa tính mạng, được coi là khẩn cấp hoặc cấp cứu và trong đó có khả năng cần phải có hành\nđộng y tế ngay lập tức để bảo toàn tính mạng hoặc ngăn ngừa sự kiện thảm khốc. Điều này khác với kết quả bất\nthường, được định nghĩa là kết quả nằm ngoài phạm vi xét nghiệm dự kiến nhưng không phải là mối đe dọa tính\nmạng khẩn cấp hoặc cấp cứu. Điều quan trọng nữa là phải phân biệt giữa các xét nghiệm quan trọng (bản thân các xét\nnghiệm chẩn đoán, một số trong số đó được bệnh viện định nghĩa là quan trọng theo bản chất) và kết quả xét nghiệm\nquan trọng (có nghĩa là kết quả của bất kỳ xét nghiệm chẩn đoán nào cho thấy tình trạng rất nghiêm trọng hoặc đe dọa\ntính mạng). Tiêu chuẩn này và các yếu tố có thể đo lường của nó liên quan đến kết quả xét nghiệm quan trọng\n(kết quả) từ bất kỳ xét nghiệm chẩn đoán nào và các thông số kết quả quan trọng này cùng phản ứng với chúng phải\nđược bệnh viện thiết lập. Ví dụ, bệnh viện có thể định nghĩa kết quả quan trọng đối với nồng độ kali là dưới 2,5\nmmol/L hoặc trên 6,0 mmol/L, cho thấy tình trạng hạ kali máu hoặc tăng kali máu có khả năng đe dọa tính mạng.\n\nCác bác sĩ chăm sóc sức khỏe tại bệnh viện có thể coi kết quả là rất nghiêm trọng trong một số tình huống lâm sàng mà\nkết quả không nằm trong phạm vi nguy cấp được xác định, chẳng hạn như nồng độ kali hơi thấp trong bối cảnh ngộ\nđộc digitalis. Tuy nhiên, các quyết định lâm sàng đó tách biệt với mục đích tuân thủ tiêu chuẩn này, yêu cầu bệnh viện\nphải chính thức xác định các thông số của phạm vi nguy cấp tuyệt đối cho các xét nghiệm, như trong ví dụ về nồng độ\nkali nguy cấp ở trên và thiết lập quy trình báo cáo và phản hồi.\n\nCác xét nghiệm chẩn đoán bao gồm tất cả các xét nghiệm, chẳng hạn như xét nghiệm trong phòng thí nghiệm, chẩn\nđoán hình ảnh và chẩn đoán tim. Kết quả nguy cấp cũng có thể được tạo ra từ bất kỳ xét nghiệm chẩn đoán nào được\nthực hiện tại giường bệnh, chẳng hạn như xét nghiệm máu tại chỗ, chụp ảnh di động và điện tâm đồ 12 chuyển đạo.\nCác xét nghiệm chẩn đoán tạo ra kết quả xét nghiệm xác định có thể chỉ ra mối đe dọa đến tính mạng khác với theo\ndõi điện tử liên tục, chẳng hạn như phép đo từ xa tim, theo dõi EEG (điện não đồ) liên tục hoặc theo dõi thai nhi.\nTheo dõi điện tử liên tục là một công cụ đánh giá lâm sàng được sử dụng để phát hiện những thay đổi về tình trạng\ncủa bệnh nhân theo thời gian có thể xác định mối đe dọa đến tính mạng nhưng không được thiết kế để tạo ra kết quả\nnguy cấp được xác định.\n\nMột hệ thống báo cáo chính thức được sử dụng trong toàn bộ bệnh viện, hệ thống này xác định rõ ràng cách thức\ntruyền đạt kết quả quan trọng của các xét nghiệm chẩn đoán cho các bác sĩ và cách thức thông tin được ghi chép\nvà hành động. Điều này phải bao gồm giao tiếp vòng kín bằng cách đọc lại giữa người báo cáo và người nhận. Mục\ntiêu là cung cấp các kết quả quan trọng trong một khung thời gian đã thiết lập để nhà cung cấp dịch vụ chăm sóc sức\nkhỏe được cấp phép có trách nhiệm có thể đánh giá tầm quan trọng của kết quả và hành động dựa trên các kết quả\ntrong một khung thời gian xác định.\n\nTổ chức phải xác định các xét nghiệm có thể có kết quả quan trọng và đào tạo nhân viên lâm sàng về các xét nghiệm\nnày là gì và cách nhận biết kết quả quan trọng.\n\nTổ chức triển khai một giao thức mô tả cách nhận biết, ghi chép và truyền đạt kết quả quan trọng cho nhà cung cấp\nchịu trách nhiệm chăm sóc bệnh nhân, cũng như khung thời gian báo cáo và phản hồi kết quả quan trọng, bao gồm\nghi chép các hành động đã thực hiện khi có thể. Điều này phải bao gồm cách tiến hành khi cá nhân thực hiện xét\nnghiệm cũng là cá nhân chịu trách nhiệm giải thích và phản hồi xét nghiệm; ví dụ, khi bác sĩ tim mạch thực hiện và\ngiải thích điện tâm đồ 12 chuyển đạo cho bệnh nhân mà họ đang điều trị hoặc khi bác sĩ thực hiện xét nghiệm là bác\nsĩ đang điều trị cho bệnh nhân. Trong những trường hợp này, việc báo cáo kết quả quan trọng là không cần thiết.\n\nNgoài việc xác định rõ ràng cách truyền đạt kết quả và khung thời gian bắt buộc để thực hiện, tổ chức phải triển\nkhai một giao thức mô tả cách bác sĩ điều trị dự kiến sẽ phản hồi và trong khung thời gian nào. Sau đó, bệnh viện\nphải theo dõi việc tuân thủ các giao thức và khung thời gian nêu trên đối với các kết quả quan trọng và hành động\nkhi quan sát thấy xu hướng tiêu cực hoặc xảy ra các sự kiện bất lợi. Ví dụ, việc lưu giữ nhật ký trong phòng xét\nnghiệm để ghi lại thời gian báo cáo kết quả quan trọng và bao gồm mã định danh bệnh nhân và tên nhân viên đã\nnhận báo cáo là một cách để đơn giản hóa việc theo dõi việc tuân thủ.\n\nCác yếu tố đo lường được của IPSG.02.00\n1. Bệnh viện xác định, bằng văn bản, các kết quả xét nghiệm quan trọng có thể biểu thị các giá trị đe dọa tính mạng\nkhẩn cấp hoặc cấp cứu đối với các xét nghiệm chẩn đoán. (Xem thêm AOP.03.02, ME 3)\n2. Bệnh viện xây dựng một quy trình báo cáo chính thức xác định cách thức báo cáo/truyền đạt kết quả quan trọng\ncủa các xét nghiệm chẩn đoán cho các bác sĩ và khung thời gian dự kiến để báo cáo các kết quả quan trọng.\n3. Bệnh viện xác định thông tin kết quả quan trọng nào được ghi lại trong hồ sơ y tế.\n4. Bệnh viện giám sát việc tuân thủ các khung thời gian đã xác định để báo cáo và hành động đối với các kết quả\nquan trọng, và ghi lại các hành động được thực hiện khi không đáp ứng được khung thời gian.","m":[],"sec":"Mục tiêu 2: Cải thiện giao tiếp hiệu quả"},{"c":"IPSG.02.01","ch":"IPSG","t":"Bệnh viện triển khai quy trình chuẩn hóa cho việc trao đổi thông tin.","p":"Sự cố giao tiếp có thể xảy ra trong bất kỳ quá trình chuyển giao chăm sóc bệnh nhân nào và có thể dẫn đến các\nsự kiện an toàn cho bệnh nhân. Giao tiếp chuyển giao cũng có thể được gọi là giao tiếp chuyển giao. Việc\nchuyển giao chăm sóc bệnh nhân trong bệnh viện diễn ra theo những cách sau:\n• Giữa các bác sĩ chăm sóc sức khỏe (ví dụ: bác sĩ với bác sĩ, bác sĩ với y tá, y tá với y tá)\n• Giữa các cấp độ chăm sóc khác nhau trong cùng một bệnh viện (ví dụ: khi bệnh nhân được chuyển từ khoa\nchăm sóc tích cực sang khoa y tế hoặc từ khoa cấp cứu sang phòng phẫu thuật)\n• Từ khoa nội trú đến khoa chẩn đoán hoặc khoa điều trị khác, chẳng hạn như khoa X quang hoặc khoa vật lý\ntrị liệu\n• Giữa nhân viên và bệnh nhân/gia đình, chẳng hạn như khi xuất viện\n\nSự gián đoạn và các yếu tố gây xao nhãng khác từ các hoạt động của khoa có thể cản trở việc truyền đạt rõ ràng\nthông tin quan trọng của bệnh nhân. Nội dung và quy trình chuẩn hóa, quan trọng để giao tiếp giữa bệnh\nnhân, gia đình, người chăm sóc và nhóm chăm sóc sức khỏe có thể cải thiện đáng kể kết quả liên quan đến việc\nchuyển giao chăm sóc bệnh nhân.\n\nCác biểu mẫu, công cụ hoặc phương pháp chuẩn hóa hỗ trợ quy trình chuyển giao nhất quán và đầy đủ. Nội\ndung của thông tin liên lạc bàn giao và hình thức, công cụ hoặc phương pháp được sử dụng được chuẩn hóa\ncho loại bàn giao. Quy trình bàn giao có thể khác nhau đối với các loại bàn giao khác nhau trong bệnh viện. Ví\ndụ, việc bàn giao chăm sóc bệnh nhân từ khoa cấp cứu sang khoa nội có thể yêu cầu quy trình khác hoặc nội\ndung khác so với việc bàn giao từ phòng phẫu thuật sang khoa chăm sóc đặc biệt; tuy nhiên, việc bàn giao được\nchuẩn hóa cho loại bàn giao diễn ra\n\nCác biện pháp thực hành an toàn để giao tiếp hiệu quả bao gồm:\n•\nSử dụng nội dung và quy trình chuẩn hóa, quan trọng để giao tiếp giữa bệnh nhân, gia đình, bác sĩ chăm sóc sức\nkhỏe và những người khác tham gia vào việc chăm sóc bệnh nhân trong quá trình chuyển giao dịch vụ chăm sóc\nbệnh nhân\n•\nSử dụng các phương pháp, biểu mẫu hoặc công cụ chuẩn hóa để tạo điều kiện thuận lợi cho việc chuyển giao\ndịch vụ chăm sóc bệnh nhân một cách nhất quán và đầy đủ\n•\nQuá trình chuyển giao phải cho phép những người tham gia có cơ hội làm rõ thông tin trong quá trình chuyển\ngiao, bằng cách tạo cơ hội để đặt câu hỏi hoặc để thảo luận giữa người cung cấp và người nhận thông tin. Tuy\nnhiên, có thể chấp nhận thảo luận diễn ra ngoài các tương tác trực tiếp, chẳng hạn như qua điện thoại, tin\nnhắn văn bản hoặc các hình thức giao tiếp khác.\n\nCác biểu mẫu hoặc công cụ chuyển giao, nếu được bệnh viện sử dụng, không bắt buộc phải là một phần\ncủa hồ sơ y tế. Ngoài ra, thông tin chi tiết được truyền đạt trong quá trình chuyển giao không bắt\nbuộc phải được ghi lại trong hồ sơ y tế; tuy nhiên, bệnh viện có thể muốn có tài liệu chứng minh\nrằng quá trình chuyển giao đã diễn ra. Ví dụ,\nngười hành nghề chăm sóc sức khỏe sẽ ghi lại rằng họ đã hoàn thành việc bàn giao và họ đã chuyển giao\ntrách nhiệm chăm sóc cho ai, sau đó ký, ghi ngày và giờ vào mục nhập\n\nCác yếu tố đo lường được của IPSG.02.01\n1.\nBệnh viện thực hiện một quy trình chuẩn hóa để truyền đạt thông tin quan trọng giữa các bác sĩ\nchăm sóc sức khỏe trong quá trình bàn giao chăm sóc bệnh nhân.\n2.\nBệnh viện sử dụng các biểu mẫu, công cụ hoặc phương pháp chuẩn hóa hỗ trợ quy trình bàn giao\nthống nhất và đầy đủ, bao gồm cơ hội cho tất cả nhân viên liên quan làm rõ thông tin và đặt câu hỏi.\n3. Bệnh viện thu thập, phân tích, theo dõi và xu hướng dữ liệu cho các sự kiện an toàn bệnh nhân liên quan đến việc bàn\ngiao.\n\nMục tiêu 3: Cải thiện tính an toàn của thuốc","m":[],"sec":"Mục tiêu 2: Cải thiện giao tiếp hiệu quả"},{"c":"IPSG.03.00","ch":"IPSG","t":"Bệnh viện triển khai quy trình cải thiện tính an toàn của thuốc có mức cảnh báo cao.","p":"Sai sót về thuốc có mức cảnh báo cao có thể dẫn đến thương tích hoặc tử vong cho bệnh nhân và có khả năng phát\nsinh thêm chi phí liên quan đến việc chăm sóc những bệnh nhân này. Viện Thực hành Thuốc An toàn (ISMP) định\nnghĩa thuốc có mức cảnh báo cao là \"thuốc có nguy cơ gây hại đáng kể cho bệnh nhân khi sử dụng nhầm. Mặc dù sai\nsót có thể phổ biến hơn hoặc không phổ biến hơn đối với những loại thuốc này, nhưng hậu quả của sai sót rõ ràng là\ntàn khốc hơn đối với bệnh nhân\". Các ví dụ thường được trích dẫn nhất về thuốc có mức cảnh báo cao bao gồm:\n• Insulin\n• Thuốc phiện\n• Thuốc hóa trị liệu\n• Thuốc chống huyết khối\n• Thuốc chống đông máu\n• Thuốc tiêu huyết khối\n• Thuốc có phạm vi điều trị hẹp (ví dụ, digitalis)\n• Thuốc chẹn thần kinh cơ\n• Thuốc ngoài màng cứng hoặc nội tủy\n\nCác ví dụ về danh sách thuốc cảnh báo cao có sẵn từ các tổ chức như ISMP và Tổ chức Y tế Thế giới\n(WHO). Để quản lý an toàn, bệnh viện cần xây dựng danh sách riêng về các loại thuốc cảnh báo cao dựa\ntrên các yếu tố sau:\n• Mô hình sử dụng thuốc độc đáo của bệnh viện\n• Dữ liệu nội bộ của bệnh viện về các trường hợp suýt xảy ra tai nạn (hoặc suýt xảy ra tai nạn)\n• Sai sót về thuốc và các sự kiện báo động\n• Các vấn đề về an toàn được công bố trong tài liệu chuyên môn\n\nDanh sách bao gồm các loại thuốc được xác định là có nguy cơ cao gây ra các kết quả bất lợi. Thông tin từ\ntài liệu và/hoặc Bộ Y tế cũng có thể giúp xác định loại thuốc nào nên được đưa vào. Danh sách này được\ncập nhật ít nhất hàng năm. Danh sách có thể cần được cập nhật thường xuyên hơn nếu có sự bổ sung hoặc\nthay đổi đối với các dịch vụ bệnh viện, nhóm bệnh nhân hoặc các loại thuốc mới được thêm vào danh mục\nthuốc của bệnh viện được coi là có nguy cơ cao.\n\nMột số loại thuốc/nhóm thuốc cảnh báo cao (như thuốc chẹn thần kinh cơ) có\nbộ rủi ro cụ thể riêng ngoài những rủi ro tồn tại chỉ dựa trên nhóm thuốc cảnh báo cao. Các chiến lược để\nngăn ngừa\ntác hại nên dựa trên hồ sơ rủi ro cụ thể của loại thuốc/loại thuốc đó, trong trường hợp đó. Một số loại\nthuốc có mức cảnh báo cao\ncó thể không yêu cầu các chiến lược bổ sung ngoài các chiến lược chuẩn hóa do bệnh viện áp dụng. Bệnh\nviện phải xác định khi nào cần có chiến lược phù hợp và các biện pháp chuẩn hóa. Ví dụ, thuốc chẹn thần\nkinh cơ có thể vô tình được lấy ra khỏi kho lạnh khi được bảo quản cùng với các loại thuốc khác được bảo\nquản lạnh. Một ví dụ về chiến lược để giảm thiểu rủi ro này là bảo quản các thuốc chẹn thần kinh cơ tách\nbiệt với các loại thuốc khác, chẳng hạn như trong các hộp có nắp, với nhãn cảnh báo nổi bật trên hộp và các\nloại thuốc bên trong. Các ví dụ khác là thuốc hóa trị, do tính phức tạp của các đơn thuốc và phác đồ điều trị\nvà do đặc tính của một số loại thuốc này, chẳng hạn như những loại thuốc có thể gây hoại tử mô khi xảy ra\ntình trạng thoát mạch. Các ví dụ về chiến lược cho các loại thuốc đó bao gồm các phác đồ đặt thuốc hóa trị,\nsử dụng các đường truyền trung tâm để truyền thuốc, các phác đồ theo dõi bệnh nhân trong quá trình\ntruyền thuốc và các bộ dụng cụ thoát mạch có sẵn.\n\nMột ví dụ cụ thể về phương pháp thực hành tốt nhất về thuốc cảnh báo cao được ISMP xác định liên quan\nđến việc phân phối vincristine (và các ancaloit vinca khác) trong một túi nhỏ có dung dịch tương thích chứ\nkhông phải trong ống tiêm. Các biến cố bất lợi đáng kể dẫn đến tổn thương thần kinh nghiêm trọng và\nthường tử vong đã xảy ra do vô tình sử dụng ancaloit vinca qua đường nội tủy. Trong các tổ chức phân phối\nancaloit vinca trong một túi nhỏ, không có trường hợp nào được báo cáo về việc vô tình sử dụng ancaloit\nvinca qua đường nội tủy. Phương pháp thực hành tốt nhất này được các tổ chức sau hỗ trợ:\n• ISMP\n• Ủy ban chung và Ủy ban chung quốc tế\n• Tổ chức Y tế Thế giới (WHO)\n• Hiệp hội Ung thư Lâm sàng Hoa Kỳ (ASCO)\n• Hiệp hội Điều dưỡng Ung thư (ONS)\n• Mạng lưới Ung thư Toàn diện Quốc gia\nTuy nhiên, quy trình chung để quản lý thuốc cảnh báo cao vẫn phải được chuẩn hóa trong toàn bộ bệnh\nviện, chẳng hạn như dán nhãn thuốc cảnh báo cao theo tiêu chuẩn và yêu cầu quy trình kiểm tra lại. Các ví\ndụ về các chiến lược giảm thiểu rủi ro được điều chỉnh bổ sung nên được thêm vào quy trình chuẩn hóa\ncủa bệnh viện.\nHướng dẫn bổ sung cho việc này được giải thích bên dưới. Bệnh viện phải đào tạo nhân viên lâm sàng và\nkỹ thuật xử lý thuốc có rủi ro cao về quy trình chuẩn hóa, các rủi ro liên quan đến từng loại thuốc và các\nchiến lược giảm thiểu rủi ro cho từng loại thuốc.\n\nBệnh viện phải lập danh sách các loại thuốc có cảnh báo cao được dự trữ và sử dụng trong bệnh viện. Danh\nsách các loại thuốc có cảnh báo cao phải đáp ứng các tiêu chí sau:\n• Cập nhật\n• Được xem xét ít nhất hàng năm và khi các loại thuốc mới được thêm vào danh mục thuốc\n• Được nhân viên lâm sàng biết đến\n\n•\nĐi kèm với các chiến lược giảm thiểu rủi ro mạnh mẽ, được phát triển tốt giúp giảm thiểu rủi ro\nsai sót và giảm thiểu tác hại\n\nCác chiến lược phải được áp dụng cho tất cả các khoa và dịch vụ của bệnh viện và có thể duy trì theo thời gian.\nTheo\nISMP, các ví dụ về những chiến lược này bao gồm:\n• Chuẩn hóa các quy trình liên quan đến việc đặt hàng, lưu trữ, chuẩn bị và quản lý các\nloại thuốc này\n• Cải thiện khả năng tiếp cận thông tin về các loại thuốc này\n• Hạn chế tiếp cận các loại thuốc có mức cảnh báo cao\n• Sử dụng thêm nhãn và cảnh báo tự động\n• Xây dựng các biện pháp dự phòng vào quy trình quản lý thuốc như kiểm tra kép tự động hoặc độc lập, các\nphương pháp an toàn như máy bơm có cơ chế khóa và giảm\ncác tùy chọn khả dụng, chẳng hạn như hạn chế nồng độ khả dụng của cùng một loại thuốc\n\nCác biện pháp can thiệp giảm thiểu rủi ro của bệnh viện phải thể hiện rõ trong chương trình quản lý thuốc tổng\nthể và trong các lĩnh vực lâm sàng nơi sử dụng các loại thuốc này. Ví dụ, heparin tiêm tĩnh mạch được sử dụng\ntrong các đơn vị chăm sóc tích cực cho trẻ sơ sinh có thể yêu cầu các chiến lược an toàn khác so với heparin tiêm\ntĩnh mạch trong khoa cấp cứu và điều này phải thể hiện rõ trong các lĩnh vực đó. Tuy nhiên, các chiến lược chung\nnhư nhãn đặc biệt cho các loại thuốc có mức cảnh báo cao và quy trình kiểm tra kép phải được chuẩn hóa trong\ntoàn bộ bệnh viện để tránh nhầm lẫn.\n\nCác yếu tố đo lường được của IPSG.03.00\n1. Bệnh viện xác định, bằng văn bản, danh sách các loại thuốc cảnh báo cao của mình. (Xem thêm MMU.02.00, ME 1)\n2. Bệnh viện thực hiện chiến lược giảm thiểu rủi ro để giảm nguy cơ gây hại từ các loại thuốc cảnh báo cao, chiến lược\nnày thống nhất trong toàn bệnh viện và ngoài ra, bao gồm các chiến lược phù hợp cho các loại thuốc cụ thể khi cần thiết.\n3. Bệnh viện xem xét và, nếu cần thiết, sửa đổi danh sách các loại thuốc cảnh báo cao của mình hàng năm ít nhất.","m":[],"sec":"Mục tiêu 3: Cải thiện tính an toàn của thuốc"},{"c":"IPSG.03.01","ch":"IPSG","t":"Bệnh viện triển khai quy trình cải thiện tính an toàn của các loại thuốc có tên gọi/tên gọi tương tự.","p":"Thuốc có bao bì sản phẩm tương tự hoặc có tên nghe giống nhau có thể dễ bị các bác sĩ chăm sóc sức khỏe nhầm\nlẫn và có thể dẫn đến các lỗi dùng thuốc có khả năng gây hại. Tên giống nhau/phát âm giống nhau (LASA) là tên\nthuốc trông hoặc phát âm giống như tên thuốc khác khi viết hoặc nói. Bao bì thuốc giống nhau là hộp đựng thuốc\nhoặc bao bì chính trông giống như hộp đựng thuốc hoặc bao bì chính của thuốc khác. Có nhiều tên thuốc nghe\nhoặc phát âm giống như tên thuốc khác. Ví dụ, dopamine và dobutamine nghe giống nhau và tên in cũng có thể\ntrông giống nhau trong một số ngôn ngữ như tiếng Anh. Tên gây nhầm lẫn là nguyên nhân phổ biến gây ra lỗi\ndùng thuốc trên toàn thế giới. Các yếu tố sau đây góp phần gây ra sự nhầm lẫn này:\n• Không biết đầy đủ về tên thuốc\n• Sản phẩm mới có sẵn\n• Bao bì hoặc nhãn tương tự\n• Sử dụng lâm sàng tương tự\n• Đơn thuốc không rõ ràng hoặc hiểu lầm trong quá trình cấp đơn thuốc bằng lời nói\n\nBệnh viện phải thiết lập các chiến lược quản lý rủi ro để tránh nhầm lẫn với thuốc LASA và tăng cường an toàn\ncho bệnh nhân. Bệnh viện phải xác định loại thuốc nào cần có biện pháp bảo vệ để ngăn ngừa nhầm lẫn liên quan\nđến LASA có thể gây ra lỗi. Các chiến lược có thể bao gồm nhưng không giới hạn ở những điều sau:\n• Bao gồm mục đích của thuốc trên đơn thuốc\n• Cấu hình các biện pháp bảo vệ trong hệ thống đặt thuốc bằng máy tính để yêu cầu số lượng chữ cái tối thiểu,\nchẳng hạn như ít nhất năm chữ cái, khi các bác sĩ đang tìm kiếm một loại thuốc\n\n• Thay đổi giao diện của tên thuốc trông giống nhau (ví dụ, sử dụng “chữ TALLman” trên nhãn như\nDOBUTamine và DOPamine hoặc oxyBUTYnin và oxyCONTIN)\n\nKhi không thể sử dụng các phương pháp được đề xuất ở trên, bệnh viện phải triển khai một chiến lược\nthay thế để ngăn ngừa lỗi LASA. Bệnh viện cũng nên cập nhật các chiến lược mới nổi để ngăn ngừa lỗi\nLASA khi có thể và khi có đủ nguồn lực. Các ví dụ bao gồm:\n•\nCấu hình màn hình lựa chọn máy tính và menu thả xuống trong hệ thống kê đơn để ngăn\n•\ntên LASA xuất hiện cạnh nhau\n•\nPhân phối tự động bằng các thiết bị điện tử và công nghệ tuần tự hóa\n•\nSử dụng hệ thống vòng kín với công nghệ mã vạch để tăng khả năng đọc nhãn giống nhau\n•\nXem xét các lỗi LASA tiềm ẩn khi sắp xếp lại kho hoặc đưa ra quyết định mua hàng\n\nBệnh viện nên cập nhật danh sách thuốc LASA thường xuyên, vì các loại thuốc mới được chấp thuận\nhoặc tên thương mại của thuốc thay đổi. Rủi ro đối với các lỗi liên quan đến LASA không chỉ giới hạn ở\nviệc kê đơn và phân phối. Các chiến lược khác để ngăn ngừa lỗi LASA bao gồm tránh lưu trữ các loại\nthuốc này gần nhau, nơi bác sĩ chăm sóc sức khỏe có thể vô tình lấy nhầm thuốc để phân phối hoặc\ndùng. Quy trình của bệnh viện cũng nên bao gồm một cơ chế để đánh giá xem có rủi ro LASA hay không\nkhi bệnh viện phải thay thế thuốc để giải quyết tình trạng thiếu hụt (ví dụ, khi thay thế một nhãn hiệu\nthuốc khác có bao bì tương tự như một loại thuốc khác trong danh mục thuốc hiện có hoặc có tên\nthương mại khác với tên gốc tương tự như một loại thuốc khác). Bệnh viện nên triển khai một cách tiếp\ncận toàn diện đối với việc quản lý thuốc LASA, từ thời điểm đặt hàng thuốc dự trữ, nơi đưa ra quyết\nđịnh liên quan đến các nhãn hiệu (tên thương mại của thuốc, hình thức nhãn), trong suốt quá trình liên\ntục cho đến đội ngũ nhân viên tuyến đầu xử lý và cấp phát thuốc. Bệnh viện phải đào tạo đội ngũ nhân\nviên lâm sàng và kỹ thuật xử lý thuốc LASA về quy trình chuẩn hóa, các rủi ro liên quan đến từng loại\nthuốc và các chiến lược giảm thiểu rủi ro cho từng loại thuốc.\n\nCác yếu tố đo lường được của IPSG.03.01\n1. Bệnh viện xác định, bằng văn bản, danh sách các loại thuốc có tên giống nhau/có âm thanh giống nhau. (Xem\nthêm MMU.02.00, ME 1; MMU.07.01, ME 2)\n2. Bệnh viện triển khai một quy trình quản lý các loại thuốc có tên giống nhau/có âm thanh giống nhau toàn diện\nvà thống nhất trong toàn bệnh viện. (Xem thêm MMU.07.01, ME 2)\n3. Bệnh viện xem xét và sửa đổi, khi cần thiết, danh sách các loại thuốc có tên giống nhau/có âm thanh giống nhau\nhàng năm ít nhất.","m":[],"sec":"Mục tiêu 3: Cải thiện tính an toàn của thuốc"},{"c":"IPSG.03.02","ch":"IPSG","t":"Bệnh viện triển khai quy trình quản lý sử dụng an toàn chất điện giải cô đặc.","p":"Việc sử dụng chất điện giải cô đặc không đúng cách hoặc không cố ý có thể là những sai lầm chết người và biện\npháp hiệu quả nhất để giảm hoặc loại bỏ những sự cố này là triển khai quy trình quản lý chất điện giải cô đặc.\nChất điện giải cô đặc là các lọ đựng các dạng chất điện giải cô đặc cần pha loãng hoặc chuẩn bị khác trước khi\ntruyền tĩnh mạch. Điều quan trọng cần phân biệt là tiêu chuẩn này không bao gồm các dạng chất điện giải cô đặc\nnhư dung dịch muối 3%–5% để truyền, vì chúng đã được pha loãng và chuẩn bị để truyền thay vì được dự trữ\ntrong các lọ cần pha loãng trước khi truyền. Chất điện giải cô đặc bao gồm nhưng không giới hạn ở những chất\nsau:\n• Kali clorua\n• Kali phosphat\n• Natri clorua\n• Magie sulfat\n\nChất điện giải cô đặc không nên có sẵn dưới dạng kho dự trữ tại bất kỳ đơn vị chăm sóc bệnh nhân nào (bao gồm cả\ntrong phòng phẫu thuật/kho dự trữ thường xuyên gây mê) càng nhiều càng tốt tùy theo khả năng của hiệu thuốc. Bất\ncứ nơi nào chất điện giải cô đặc được lưu trữ, điều quan trọng là bệnh viện phải thực hiện đánh giá rủi ro như phân\ntích chế độ lỗi và tác động (FMEA) hoặc phương pháp đánh giá rủi ro được công nhận khác để xác định và giảm\nthiểu các rủi ro tiềm ẩn liên quan đến nó. Ngoài ra, chất điện giải cô đặc phải luôn được tách biệt khỏi các loại thuốc\nkhác và chỉ những nhân viên có trình độ và được đào tạo mới được tiếp cận những loại thuốc này. Ví dụ, nếu bệnh\nviện xác định cần phải dự trữ chất điện giải cô đặc trong xe đẩy cấp cứu, thì chúng vẫn phải được tách biệt khỏi các\nloại thuốc khác trong xe đẩy với nhãn cảnh báo phù hợp, nhân viên phải được đào tạo về các rủi ro và cân nhắc về an\ntoàn, phải tiến hành đánh giá rủi ro bao gồm việc giảm thiểu các rủi ro đó và điều này phải được nêu trong chính sách\ncủa bệnh viện.\n\nChất điện giải không được phân phối dưới dạng cô đặc cho các đơn vị chăm sóc bệnh nhân cho từng bệnh nhân.\nCác trường hợp ngoại lệ đối với khuyến nghị này là đối với các lọ đựng trong bộ dụng cụ phẫu thuật tim hoặc khu\nvực lưu trữ phẫu thuật tim có khóa và chỉ dành cho nhóm phẫu thuật, magiê sunfat đựng trong xe đẩy cấp cứu hoặc\nở những khu vực có thể điều trị cho bệnh nhân tiền sản giật (phòng chuyển dạ và sinh nở, khoa cấp cứu hoặc khoa\nchăm sóc đặc biệt), natri cô đặc ở những khu vực điều trị cho bệnh nhân có thể bị tăng áp lực nội sọ (khoa chăm sóc\nđặc biệt, khoa cấp cứu và phòng phẫu thuật) và các khu vực và trường hợp đặc biệt khác do chính sách và quy trình\ncủa bệnh viện xác định.\n\nBệnh viện có thể sử dụng các biện pháp dán nhãn để giảm nguy cơ vô tình sử dụng chất điện giải cô đặc khi có thể\nlấy hoặc vận chuyển một lọ riêng lẻ từ thùng, hộp hoặc thùng chứa mở. Mỗi lọ phải được dán nhãn ngoài thùng\nchứa. Chỉ những cá nhân đủ điều kiện và được đào tạo mới được tiếp cận những lọ này.\n\nViệc quản lý liệu pháp thay thế chất điện giải cho tình trạng hạ kali máu, hạ natri máu và hạ phosphat máu là an toàn\nnhất khi sử dụng các hướng dẫn và/hoặc giao thức chuẩn hóa với chất điện giải pha loãng trước (như 20 mEq kali\nclorua trong 100 cc dung dịch muối sinh lý) và việc phân phối hoặc xử lý các lọ chất điện giải cô đặc\ntại các đơn vị chăm sóc bệnh nhân bị cấm.\n\nCác yếu tố đo lường được của IPSG.03.02\n1.\nChỉ những cá nhân đủ tiêu chuẩn và được đào tạo mới được tiếp cận với chất điện giải cô đặc và\nchúng được dán nhãn cảnh báo phù hợp và tách biệt với các loại thuốc khác trong suốt quá trình\nlưu trữ và phân phối. (Xem thêm MMU.04.00, ME 1; MMU.04.01, ME 4 và 5; MMU.05.00, ME\n1; MMU.05.03, ME 4)\n2.  Bệnh viện chỉ lưu trữ các lọ chất điện giải cô đặc bên ngoài hiệu thuốc cho các trường hợp khẩn\ncấp hoặc mục đích cụ thể và những điều này được xác định rõ ràng trong chính sách của bệnh\nviện. (Xem thêm MMU.03.00, ME 1 và 2)\n3. Bệnh viện thực hiện đánh giá rủi ro chủ động ban đầu và liên tục ít nhất hàng năm cho tất cả các khu vực\nlưu trữ chất điện giải cô đặc\n\nMục tiêu 4: Đảm bảo phẫu thuật an toàn","m":[],"sec":"Mục tiêu 3: Cải thiện tính an toàn của thuốc"},{"c":"IPSG.04.00","ch":"IPSG","t":"Bệnh viện thực hiện quy trình xác minh trước phẫu thuật và đánh dấu vị trí phẫu thuật/xâm lấn.","p":"Phẫu thuật nhầm bệnh nhân, nhầm vị trí và nhầm thủ thuật có thể gây ra rủi ro cho các sự kiện an toàn bệnh nhân\nđáng kể dẫn đến thương tích cho bệnh nhân. Các sự kiện phẫu thuật nhầm bệnh nhân, nhầm vị trí và nhầm thủ\nthuật có thể là kết quả của\n\nviệc giao tiếp không hiệu quả hoặc không đầy đủ giữa các thành viên trong nhóm thực hiện phẫu thuật\nhoặc thủ thuật xâm lấn. Sau đây là các yếu tố rủi ro phổ biến đối với các sự kiện phẫu thuật này:\n• Thiếu quy trình chuẩn hóa để đánh dấu vị trí thủ thuật\n• Sử dụng các dấu hiệu vị trí không rõ ràng, chẳng hạn như \"X\" (có thể hiểu là \"không phẫu thuật ở đây\"\nthay vì đánh dấu vị trí phẫu thuật)\n• Sử dụng vật liệu hoặc phương tiện có thể dễ dàng loại bỏ, chẳng hạn như băng dính hoặc mực bị rửa\ntrôi trong\nquá trình chuẩn bị da\n• Bệnh nhân không tham gia vào việc đánh dấu vị trí\n• Đánh giá bệnh nhân không đầy đủ\n• Xem xét hồ sơ y tế không đầy đủ\n• Văn hóa không hỗ trợ giao tiếp cởi mở giữa các thành viên trong nhóm\n• Các vấn đề liên quan đến chữ viết tay không rõ ràng\n• Sử dụng chữ viết tắt\nCác thủ thuật phẫu thuật và xâm lấn bao gồm tất cả các thủ thuật liên quan đến việc rạch hoặc chọc, bao\ngồm nhưng không giới hạn ở những thủ thuật sau:\n• Các thủ thuật phẫu thuật mở\n• Chọc hút qua da\n• Các mũi tiêm được chọn\n• Sinh thiết\n• Các thủ thuật chẩn đoán hoặc can thiệp tim mạch và mạch máu qua da\n• Nội soi ổ bụng\n• Nội soi\n• Chèn đường truyền trung tâm bên ngoài vị trí phẫu thuật nhà hát\nCác tổ chức cần xác định tất cả các khu vực trong bệnh viện nơi diễn ra các thủ thuật phẫu thuật và xâm\nlấn. Các ví dụ bao gồm:\n• Phòng thông tim\n• Khoa X quang can thiệp\n• Phòng xét nghiệm tiêu hóa\n• Đơn vị chăm sóc đặc biệt hoặc chăm sóc tích cực\nCách tiếp cận của bệnh viện để đảm bảo phẫu thuật an toàn áp dụng cho tất cả các khu vực của bệnh viện\nnơi diễn ra các thủ thuật phẫu thuật và xâm lấn.\nGiao thức chung của Ủy ban chung (Hoa Kỳ) về phòng ngừa phẫu thuật nhầm vị trí, nhầm thủ thuật và\nnhầm người™ dựa trên một phần nguyên tắc sử dụng nhiều chiến lược để đạt được mục tiêu luôn xác\nđịnh đúng bệnh nhân, đúng thủ thuật và đúng vị trí. Các yếu tố thiết yếu của Giao thức chung là quy trình\nxác minh trước phẫu thuật, đánh dấu vị trí phẫu thuật và thời gian chờ được tổ chức ngay trước khi bắt\nđầu thủ thuật.\nQuy trình xác minh trước phẫu thuật\nXác minh trước phẫu thuật là một quá trình liên tục thu thập và xác nhận thông tin. Mục đích của quá trình xác\nminh trước phẫu thuật là thực hiện các bước sau:\n• Xác minh đúng bệnh nhân, quy trình và vị trí.\n• Đảm bảo rằng tất cả các tài liệu, hình ảnh và nghiên cứu có liên quan đều có sẵn, được dán nhãn đúng cách và\nđược hiển thị.\n• Xác minh rằng bất kỳ sản phẩm máu, thiết bị y tế đặc biệt và/hoặc cấy ghép nào đều có sẵn.\n\nCó nhiều yếu tố khác nhau của quy trình xác minh trước phẫu thuật có thể được hoàn thành trước khi bệnh\nnhân đến khu vực trước phẫu thuật—chẳng hạn như đảm bảo rằng các tài liệu, hình ảnh, kết quả xét nghiệm và\ngiấy tờ được dán nhãn đúng cách và khớp với các thông tin nhận dạng của bệnh nhân. Việc chờ đến khi hết thời\ngian chờ để hoàn tất quy trình xác minh trước phẫu thuật có thể làm chậm trễ không cần thiết ca phẫu thuật\nnếu giấy tờ hoặc hình ảnh không được dán nhãn hoặc không có sẵn khi ca phẫu thuật sắp bắt đầu. Rất có thể\nmột số phần của quá trình xác minh trước phẫu thuật có thể diễn ra nhiều lần và ở nhiều nơi. Ví dụ, có thể lấy\nđược sự đồng ý phẫu thuật tại phòng khám của bác sĩ phẫu thuật, sau đó xác minh rằng quá trình này đã hoàn tất\ncó thể diễn ra tại khu vực giữ bệnh nhân trước phẫu thuật.\n\nĐánh dấu vị trí\nĐánh dấu vị trí phẫu thuật/xâm lấn liên quan đến bệnh nhân và được thực hiện bằng một dấu hiệu dễ nhận\nbiết và rõ ràng ngay lập tức. Lý tưởng nhất là không sử dụng dấu “X” làm dấu, vì nó có thể được hiểu là\n“không phải ở đây” hoặc “bên sai” và có khả năng dẫn đến sai sót trong việc chăm sóc bệnh nhân, cũng không\nnên sử dụng các dấu hiệu mơ hồ khác như đường kẻ hoặc dấu chấm. Dấu hiệu phải nhất quán trong toàn bộ\nbệnh viện. Vị trí được đánh dấu trong mọi trường hợp liên quan đến bên, nhiều cấu trúc (ngón tay, ngón\nchân, tổn thương) hoặc nhiều mức (cột sống). Khi một bác sĩ gây mê\nthực hiện một thủ thuật, chẳng hạn như gây tê vùng, liên quan đến bất kỳ yếu tố nào ở trên, bác sĩ đó cũng\nphải đánh dấu vị trí ngoài việc bác sĩ phẫu thuật đánh dấu vị trí phẫu thuật. Bác sĩ thực hiện thủ thuật xâm lấn\nphải là người đánh dấu vị trí.\n\nViệc đánh dấu vị trí phẫu thuật có thể được thực hiện tại khu vực giữ trước phẫu thuật, đơn vị phẫu thuật\ntrong ngày (DSU) và tại các đơn vị bệnh nhân, trước khi vào phòng phẫu thuật/thủ thuật bởi một bác sĩ sẽ\ntham gia trong toàn bộ quá trình. Trong trường hợp phẫu thuật, bác sĩ phẫu thuật thực hiện phẫu thuật phải\nđánh dấu vị trí. Có nhiều chức danh khác nhau được sử dụng cho bác sĩ phẫu thuật chịu trách nhiệm, chẳng\nhạn như bác sĩ phẫu thuật tham gia hoặc bác sĩ tư vấn. Đối với các thủ thuật xâm lấn không phẫu thuật, bác sĩ\nđa khoa có thể là người thực hiện thủ thuật. Bệnh viện phải xác định người được phép thực hiện đánh dấu vị\ntrí phẫu thuật trong chính sách và thủ tục hoặc các tài liệu quản lý của nhân viên y tế.\n\nCó những trường hợp khi một học viên hoặc người được ủy quyền khác có thể thực hiện việc đánh dấu vị\ntrí—đó là khi học viên thực hiện toàn bộ quy trình, yêu cầu giám sát tối thiểu hoặc không có giám sát từ bác sĩ\nphẫu thuật hoặc bác sĩ chịu trách nhiệm. Trong những trường hợp này, học viên đánh dấu vị trí phẫu thuật.\nKhi học viên hỗ trợ bác sĩ phẫu thuật hoặc bác sĩ chịu trách nhiệm, chỉ bác sĩ phẫu thuật hoặc bác sĩ mới được\nphép thực hiện việc đánh dấu vị trí.\n\nViệc đánh dấu vị trí có thể diễn ra bất kỳ lúc nào trước khi bắt đầu thủ thuật phẫu thuật/xâm lấn, miễn là\nbệnh nhân tích cực tham gia vào việc đánh dấu vị trí bất cứ khi nào có thể và dấu hiệu có thể nhìn thấy sau khi\nbệnh nhân được chuẩn bị và mặc quần áo. Ví dụ về trường hợp bệnh nhân không thể tham gia bao gồm:\n• Bệnh nhân không đủ năng lực để đưa ra quyết định chăm sóc sức khỏe\n• Trẻ em\n• Bệnh nhân cần phẫu thuật khẩn cấp\n\nBệnh viện có một quy trình thay thế để xác định đúng vị trí trong những trường hợp mà việc đánh dấu vị trí có\nthể gây hại, chẳng hạn như trẻ sinh non hoặc khi bệnh nhân từ chối đánh dấu vị trí, và điều này cần được nêu\ntrong các chính sách và quy trình. Đánh dấu vị trí phải được đặt ở nơi có thể nhìn thấy sau khi phủ khăn lên vị\ntrí phẫu thuật, để có thể xác minh trong thời gian chờ cuối cùng.\n\nCác yếu tố đo lường được của IPSG.04.00\n1.Bệnh viện thực hiện quy trình xác minh trước phẫu thuật bằng cách sử dụng danh sách kiểm tra hoặc cơ\nchế khác để ghi lại quá trình xác minh sau đây:\n• Sự đồng ý có thông tin phù hợp với quy trình\n• Đúng bệnh nhân, đúng quy trình và đúng vị trí\n• Tất cả các tài liệu, sản phẩm máu, thiết bị y tế và thiết bị y tế cấy ghép bắt buộc\nđều có sẵn, đúng và hoạt động\n• Có nguy cơ mất máu > 500 mL (7 mL/kg ở trẻ em) hay không\n• Bệnh nhân có đường thở khó hoặc nguy cơ hít phải hay không\n• Bất kỳ dị ứng nào đã biết\n(Xem thêm PCC.03.00, ME 2)\n2. Bệnh viện sử dụng dấu hiệu dễ nhận biết và rõ ràng để xác định vị trí phẫu thuật/\nxâm lấn thống nhất trong toàn bệnh viện.\n3. Quy trình đánh dấu vị trí phẫu thuật/xâm lấn bao gồm các nội dung sau:\n• Đánh dấu do người thực hiện thủ thuật hoàn thành\n• Bệnh nhân tham gia vào quy trình đánh dấu\n• Quy trình đánh dấu vị trí thay thế cho các trường hợp đánh dấu có thể gây hại\n• Quy trình xác định vị trí thay thế cho những bệnh nhân từ chối đánh dấu vị trí\n• Các kỹ thuật đánh dấu vị trí thay thế cho các tình huống không thể đánh dấu vị trí thông thường (ví dụ:\nlaser, xạ phẫu định vị, nha khoa)","m":[],"sec":"Mục tiêu 4: Đảm bảo phẫu thuật an toàn"},{"c":"IPSG.04.01","ch":"IPSG","t":"Bệnh viện thực hiện quy trình tạm dừng được thực hiện ngay trước khi bắt đầu thủ thuật phẫu thuật/xâm lấn và thủ thuật đăng xuất được thực hiện sau thủ thuật.","p":"Thời gian chờ cho phép giải quyết mọi câu hỏi chưa được trả lời hoặc nhầm lẫn và cung cấp cơ hội cuối cùng để xác\nđịnh các lỗi tiềm ẩn như phẫu thuật sai vị trí, phẫu thuật sai bệnh nhân hoặc phẫu thuật sai thủ thuật cho đúng bệnh\nnhân. Quy trình đăng xuất sau phẫu thuật cho phép xác định các khu vực cần cải thiện và thảo luận về những gì đã\ndiễn ra tốt đẹp trong quá trình phẫu thuật để hỗ trợ bệnh viện đưa ra quyết định về quy trình phẫu thuật tổng thể.\n\nQuy trình thời gian chờ áp dụng cho tất cả các thủ thuật xâm lấn phẫu thuật và không phẫu thuật. Bằng chứng cho\nthấy các thủ thuật khiến bệnh nhân gặp nhiều rủi ro nhất bao gồm các thủ thuật liên quan đến gây mê toàn thân hoặc\nan thần sâu, mặc dù các thủ thuật khác cũng có thể ảnh hưởng đến sự an toàn của bệnh nhân. Bệnh viện có thể tăng\ncường sự an toàn bằng cách xác định chính xác bệnh nhân, thủ thuật phù hợp và vị trí chính xác của thủ thuật.\n\nYêu cầu thời gian chờ dựa trên các nguyên tắc sau:\n•\nCó thể và phải ngăn ngừa phẫu thuật sai người, sai vị trí và sai thủ thuật.\n•\nCần có một phương pháp tiếp cận mạnh mẽ sử dụng nhiều chiến lược bổ sung để đạt được mục tiêu luôn\n•\nthực hiện đúng thủ thuật cho đúng người, tại đúng vị trí.\n•\nSự tham gia tích cực và sử dụng các phương pháp hiệu quả để cải thiện giao tiếp giữa tất cả các thành viên của\n•\nnhóm thủ thuật là rất quan trọng để thành công.\n•\nTrong phạm vi có thể, bệnh nhân và, nếu cần, gia đình tham gia vào quá trình này.\n•\nViệc thực hiện nhất quán một giao thức chuẩn hóa là hiệu quả nhất để đạt được sự an toàn.\n\nViệc tạm dừng được thực hiện thành công nhất ở các bệnh viện có văn hóa thúc đẩy làm việc nhóm và nơi mọi cá\nnhân đều cảm thấy được trao quyền để bảo vệ sự an toàn của bệnh nhân. Một bệnh viện nên xem xét văn hóa của\nmình khi thiết kế\n\ncác quy trình để đáp ứng yêu cầu về thời gian chờ. Ở một số bệnh viện, có thể cần phải quy định cụ thể\nhơn về một số yếu tố của Giao thức chung hoặc tạo ra các quy trình không được đề cập cụ thể trong các yêu\ncầu này.\n\nBệnh viện nên xác định thời gian và địa điểm xác minh trước thủ thuật và đánh dấu vị trí dựa trên những\ngì phù hợp nhất với hoàn cảnh riêng của họ. Tần suất và phạm vi xác minh trước thủ thuật sẽ phụ thuộc\nvào loại và mức độ phức tạp của thủ thuật. Ba thành phần của Giao thức chung\nkhông nhất thiết phải được trình bày theo thứ tự thời gian (mặc dù xác minh trước thủ thuật và đánh dấu\nvị trí diễn ra trước xác minh cuối cùng trong thời gian chờ). Xác minh trước thủ thuật, đánh dấu vị trí và\ncác thủ tục thời gian chờ phải nhất quán nhất có thể trong toàn bệnh viện.\n\nMục đích của thời gian chờ là tiến hành đánh giá cuối cùng để đảm bảo xác định đúng bệnh nhân, vị trí và\nthủ thuật. Yêu cầu này tập trung vào các đặc điểm tối thiểu của thời gian chờ. Một số người cho rằng việc\ntiến hành thời gian chờ trước khi gây mê là quan trọng vì một số lý do, bao gồm cả sự tham gia của\nbệnh nhân. Bệnh viện có thể tiến hành thời gian chờ trước khi gây mê hoặc có thể thêm thời gian chờ\nkhác vào thời điểm đó. Trong thời gian chờ, các hoạt động sẽ bị đình chỉ ở mức có thể để các thành viên\ntrong nhóm có thể tập trung vào việc xác nhận tích cực bệnh nhân, vị trí và thủ thuật.\n\nMột thành viên được chỉ định của nhóm sẽ khởi xướng thời gian chờ và bao gồm sự giao tiếp tích cực\ngiữa tất cả các thành viên có liên quan của nhóm thủ thuật. Thủ thuật không được bắt đầu cho đến khi tất\ncả các câu hỏi hoặc mối quan tâm được giải quyết. Thời gian chờ có hiệu quả nhất khi được thực hiện\nnhất quán trên toàn bệnh viện.\n\nThời gian chờ\nThời gian chờ được tổ chức ngay trước khi bắt đầu quy trình với sự có mặt của tất cả các thành viên trong nhóm.\nTrong thời gian chờ, nhóm thống nhất về các thành phần sau:\n• Nhận dạng đúng bệnh nhân (Xem thêm IPSG.01.00)\n• Quy trình đúng cần thực hiện\n• Vị trí phẫu thuật/xâm lấn đúng\n\nThời gian chờ được thực hiện tại địa điểm sẽ thực hiện quy trình khi bệnh nhân có mặt và có sự tham gia tích cực\ncủa toàn bộ nhóm. Bệnh nhân không phải tham gia vào thời gian chờ. Việc hoàn thành thời gian chờ được ghi lại và\nbao gồm ngày và giờ hoàn thành thời gian chờ. Bệnh viện xác định số lượng và loại tài liệu bổ sung. Nếu bác sĩ\nchính phải rời khỏi phòng (ví dụ, trong một ca phẫu thuật dài hoặc nhiều phần), phải bàn giao toàn bộ cho bác sĩ\nchịu trách nhiệm và bao gồm các thành phần của thời gian chờ. Hoạt động này phải được ghi lại.\n\nChờ ra viện\nDanh sách kiểm tra an toàn phẫu thuật của WHO bao gồm quy trình chờ ra viện, được tiến hành tại khu vực thực\nhiện thủ thuật trước khi bệnh nhân rời đi. Các thành phần sau của quy trình ký tên ra được một thành viên trong\nnhóm, thường là y tá, xác nhận bằng lời:\n•\nTên của thủ thuật phẫu thuật/xâm lấn đã được ghi lại/viết\n•\nHoàn thành việc đếm dụng cụ, miếng bọt biển và kim (nếu có)\n•\nGhi nhãn mẫu vật (khi có mẫu vật trong quá trình ký tên ra, nhãn sẽ được đọc to, bao gồm tên bệnh nhân)\n•\nBất kỳ vấn đề nào về thiết bị cần giải quyết (nếu có)\n•\nNhững gì diễn ra tốt đẹp và bất kỳ vấn đề nào được ghi nhận, với các biện pháp can thiệp tiếp theo thông qua các hoạt\nđộng cải thiện chất lượng khi cần thiết\n\nCác yếu tố đo lường được của IPSG.04.01\n1.\nToàn bộ nhóm tích cực tham gia vào quy trình tạm dừng, bao gồm các yếu tố sau đây trong khu vực sẽ thực\nhiện thủ thuật phẫu thuật/xâm lấn, ngay trước khi bắt đầu thủ thuật và điều này được ghi lại:\n•\nNhận dạng đúng bệnh nhân\n•\nThực hiện đúng thủ thuật\n•\nThực hiện đúng vị trí thực hiện thủ thuật phẫu thuật/xâm lấn\n2.\nTrước khi bệnh nhân rời khỏi khu vực thực hiện thủ thuật phẫu thuật/xâm lấn, một quy trình ký tên\nsẽ được tiến hành, bao gồm ít nhất các nội dung sau:\n•\nTên của thủ thuật phẫu thuật/xâm lấn đã được ghi lại/viết\n•\nHoàn thành việc đếm dụng cụ, miếng bọt biển và kim, nếu có\n•\nGhi nhãn mẫu vật\n•\nBất kỳ vấn đề nào về thiết bị cần giải quyết, nếu có\n3.\nKhi thực hiện các thủ thuật phẫu thuật/xâm lấn, bao gồm các thủ thuật y khoa và nha khoa được thực hiện\ntrong các bối cảnh khác ngoài phòng phẫu thuật, bệnh viện sử dụng các quy trình thống nhất để đảm bảo phẫu\nthuật an toàn.\n4. Khi hai hoặc nhiều thủ thuật riêng biệt được thực hiện trên cùng một bệnh nhân bởi các bác sĩ phẫu thuật\nkhác nhau, nhóm phải thực hiện một lần tạm dừng khác trước khi bắt đầu mỗi thủ thuật mới.\n\nMục tiêu 5: Giảm nguy cơ nhiễm trùng liên quan đến\nchăm sóc sức khỏe","m":[],"sec":"Mục tiêu 4: Đảm bảo phẫu thuật an toàn"},{"c":"IPSG.05.00","ch":"IPSG","t":"Bệnh viện thực hiện các hướng dẫn vệ sinh tay dựa trên bằng chứng để giảm nguy cơ nhiễm trùng liên quan đến chăm sóc sức khỏe.","p":"Vệ sinh tay đúng cách là trọng tâm để loại trừ các bệnh nhiễm trùng liên quan đến bệnh viện và các bệnh nhiễm\ntrùng khác. Các hướng dẫn vệ sinh tay dựa trên bằng chứng có sẵn từ Tổ chức Y tế Thế giới (WHO), Trung tâm\nKiểm soát và Phòng ngừa Dịch bệnh Hoa Kỳ (CDC) và nhiều tổ chức quốc gia và quốc tế khác. Bệnh viện phải\náp dụng và triển khai các hướng dẫn vệ sinh tay dựa trên bằng chứng hiện hành. Điều này bao gồm các nỗ lực\nchuẩn hóa việc thu thập dữ liệu tuân thủ vệ sinh tay và đảm bảo dữ liệu hợp lệ, chẳng hạn như người quan sát\nđược đào tạo. Các nguồn lực từ WHO và CDC bao gồm các nguồn lực để đào tạo người quan sát vệ sinh tay.\nCác hướng dẫn vệ sinh tay nên được đăng ở những khu vực thích hợp và nhân viên nên được đào tạo về các quy\ntrình rửa tay và khử trùng tay đúng cách. Xà phòng, nước máy, chất khử trùng và khăn dùng một lần được đặt ở\nnhững khu vực yêu cầu rửa tay và khử trùng tay. Không sử dụng máy sấy khí để làm khô tay tại các khu vực chăm\nsóc bệnh nhân.\n\nCác yếu tố đo lường được của IPSG.05.00\n1.\nBệnh viện áp dụng các hướng dẫn vệ sinh tay dựa trên bằng chứng hiện hành. (Xem thêm PCI.07.01, MEs\n2, 5 và 6)\n2.\nBệnh viện triển khai chương trình vệ sinh tay dựa trên bằng chứng trên toàn bệnh viện. (Xem thêm\nPCI.07.01, MEs 2, 5 và 6)\n3.\nBệnh viện thu thập và phân tích dữ liệu để tuân thủ các quy trình rửa tay và khử trùng tay\n4. theo các hướng dẫn vệ sinh tay dựa trên bằng chứng trên toàn bệnh viện.\n\nQuản lý và sử\ndụng thuốc\n\nTổng quan\nThuốc là thành phần quan trọng trong dịch vụ chăm sóc bệnh nhân và được sử dụng để chẩn đoán, điều trị\ntriệu chứng, phòng ngừa, chữa bệnh và giảm nhẹ cũng như quản lý các bệnh và tình trạng bệnh. Theo Hiệp\nhội Y tá Hoa Kỳ, gần hai phần ba dân số Hoa Kỳ dùng ít nhất một loại thuốc mỗi ngày và hơn một nửa dân số\ndùng ít nhất hai loại thuốc. Trên toàn cầu, lỗi dùng thuốc và thực hành dùng thuốc không an toàn là nguyên\nnhân hàng đầu gây ra thương tích và tác hại có thể tránh được trong hệ thống chăm sóc sức khỏe, ước tính gây\nra chi phí hàng năm là 42 tỷ đô la, không bao gồm tiền lương và năng suất bị mất. Tác hại liên quan đến thuốc\nchiếm 50% tác hại có thể phòng ngừa được báo cáo của dịch vụ chăm sóc sức khỏe, trong đó lỗi kê đơn và theo\ndõi là yếu tố rủi ro cao nhất. Ví dụ, ở Châu Âu, tỷ lệ lỗi dùng thuốc tại các bệnh viện ở giai đoạn kê đơn là\n0,3%–9,1% và từ 1,6% đến 2,1% ở giai đoạn cấp phát thuốc. Một nghiên cứu tại Vương quốc Anh ước tính\nrằng 28% trong số 237 triệu lỗi dùng thuốc xảy ra tại một thời điểm nào đó trong quá trình dùng thuốc có khả\nnăng gây ra hậu quả đáng kể về mặt lâm sàng. Nhưng nghiên cứu đó cũng phát hiện ra rằng lỗi có thể xảy ra ở\nmọi giai đoạn của quy trình quản lý thuốc: kê đơn (21,3%), phiên mã (1,4%), phân phối (15,9%), quản lý\n(54,4%) và theo dõi (7,0%). Ngoài ra, một nghiên cứu ở Tây Ban Nha đã kết luận rằng lỗi dùng thuốc chiếm\n37,4% tổng số các tác dụng phụ.\n\nMột hệ thống thuốc hỗ trợ quản lý thuốc tối ưu phải bao gồm các quy trình hỗ trợ sử dụng thuốc an toàn và\nhiệu quả. Sử dụng thuốc an toàn, hiệu quả liên quan đến nỗ lực phối hợp liên ngành của các bác sĩ chăm sóc\nsức khỏe áp dụng các nguyên tắc thiết kế quy trình, triển khai và cải tiến vào mọi khía cạnh của quy trình quản\nlý thuốc, bao gồm lựa chọn, mua sắm, lưu trữ, đặt hàng/kê đơn, phiên mã, phân phối, chuẩn bị, phân phối,\nquản lý, ghi chép và theo dõi các liệu pháp dùng thuốc. Mặc dù vai trò của các bác sĩ chăm sóc sức khỏe trong\nquản lý thuốc rất khác nhau giữa các quốc gia, nhưng các quy trình quản lý thuốc hợp lý để đảm bảo an toàn\ncho bệnh nhân là phổ biến và phải được hỗ trợ bởi bằng chứng khoa học và hướng dẫn cho người kê đơn,\nchẳng hạn như trong việc phát triển chương trình và việc sử dụng các hướng dẫn thực hành dùng thuốc được\nchấp nhận.\n\nLưu ý: Thuốc được định nghĩa là bất kỳ loại thuốc theo toa; thuốc mẫu; thuốc thảo dược; vitamin; thực phẩm\nchức năng; thuốc không kê đơn; vắc-xin; thuốc chẩn đoán và thuốc cản quang được sử dụng hoặc dùng cho\nngười để chẩn đoán, điều trị hoặc ngăn ngừa bệnh tật hoặc các tình trạng bất thường khác; thuốc phóng xạ;\nphương pháp điều trị hô hấp; dinh dưỡng ngoài đường tiêu hóa; các dẫn xuất của máu; và các dung dịch truyền\ntĩnh mạch (dạng nguyên chất, có chất điện giải và/hoặc thuốc), cũng như các dung dịch được nhóm phẫu thuật\ndùng/cung cấp cho bệnh nhân trong các thủ thuật phẫu thuật/xâm lấn.\n\nTiêu chuẩn\nSau đây là danh sách tất cả các tiêu chuẩn cho chức năng này. Chúng được trình bày ở đây để thuận tiện cho bạn mà\nkhông có các tuyên bố ý định hoặc các yếu tố có thể đo lường. Để biết thêm thông tin về các tiêu chuẩn này, vui lòng\nxem phần tiếp theo trong chương này, Tiêu chuẩn, Ý định và","m":[],"sec":"Safety Goals (IPSG)"},{"c":"MMU.01.00","ch":"MMU","t":"Bệnh viện quản lý các quy trình quản lý thuốc của mình.","p":"Thuốc là nguồn lực quan trọng trong việc chăm sóc bệnh nhân và việc quản lý thuốc phải được tổ chức hiệu\nquả và hiệu suất cao. Một hệ thống quản lý thuốc an toàn giải quyết các quy trình dùng thuốc của một tổ chức\nvà không chỉ là trách nhiệm của dịch vụ dược phẩm mà còn của các nhà quản lý và bác sĩ chăm sóc sức khỏe,\ny tá và các bác sĩ lâm sàng khác. Trách nhiệm này được chia sẻ như thế nào tùy thuộc vào cơ cấu và nhân sự\ncủa bệnh viện. Tại các bệnh viện không có hiệu thuốc, thuốc có thể được quản lý tại mỗi đơn vị lâm sàng theo\nchính sách của bệnh viện. Trong những trường hợp khác khi có hiệu thuốc trung tâm lớn, hiệu thuốc có thể tổ\nchức và kiểm soát thuốc trong toàn bộ bệnh viện. Quản lý thuốc hiệu quả bao gồm tất cả các bộ phận của\nbệnh viện—bệnh nhân nội trú, ngoại trú, các đơn vị chuyên khoa và các khu vực lâm sàng khác nơi thuốc\nđược sử dụng hoặc lưu trữ.\n\nMột cá nhân đủ điều kiện phải trực tiếp giám sát các hoạt động của hiệu thuốc hoặc dịch vụ dược phẩm, bất\nkể việc quản lý thuốc được tổ chức như thế nào trong bệnh viện. Cá nhân đó được đào tạo và nếu cần, được\ncấp phép và/hoặc chứng nhận phù hợp. Các luật và quy định hiện hành được đưa vào cơ cấu tổ chức và hoạt\nđộng của hệ thống quản lý thuốc được sử dụng trong bệnh viện. Cá nhân này hoặc một cá nhân đủ tiêu chuẩn\nkhác chịu trách nhiệm giám sát nhóm liên ngành quản lý thuốc được thành lập để phát triển các chính sách và\nquy trình cho các hoạt động quản lý thuốc trong bệnh viện. Các trách nhiệm bổ sung của nhóm quản lý thuốc\nbao gồm giám sát thuốc, ra quyết định, quản lý hàng tồn kho, chuẩn bị và phân phối, an toàn và chất lượng\nthuốc, bao gồm chuyển hướng, tác dụng phụ và báo cáo,\n\nĐể đảm bảo quản lý và sử dụng thuốc hiệu quả và hiệu suất, bệnh viện tiến hành đánh giá hệ thống ít nhất\nmột lần một năm. Đánh giá hàng năm xác định mức độ hoạt động tốt của hệ thống và cho phép bệnh viện hiểu\nđược nhu cầu và ưu tiên của việc cải thiện hệ thống liên tục về chất lượng và an toàn khi sử dụng thuốc.","m":[],"sec":"Tổ chức và Quản lý"},{"c":"MMU.01.01","ch":"MMU","t":"Bệnh viện thực hiện chương trình sử dụng thuốc kháng sinh một cách thận trọng dựa trên nguyên tắc quản lý thuốc kháng sinh.","p":"Bệnh viện phải triển khai các quy trình để đảm bảo sử dụng thuốc kháng khuẩn một cách tối ưu nhằm ngăn\nngừa sự phát triển và lây lan của vi khuẩn kháng thuốc và mang lại kết quả điều trị tốt hơn cho bệnh nhân.\nViệc sử dụng quá mức và sử dụng sai thuốc kháng khuẩn đã dẫn đến sự phát triển của các vi sinh vật kháng\nnhiều loại thuốc ngày càng kháng với các loại thuốc kháng khuẩn hiện có. Kháng thuốc kháng khuẩn đã được\nphân loại là vấn đề cấp bách về sức khỏe cộng đồng và kinh tế xã hội trên phạm vi toàn cầu. Hơn nữa, ước\ntính tình trạng kháng thuốc kháng khuẩn đã gây ra cái chết của ít nhất 1,27 triệu người trên toàn thế giới và\nliên quan đến gần 5 triệu ca tử vong vào năm 2019, và vào năm 2022 được liệt kê là một trong 10 mối đe dọa\nsức khỏe toàn cầu hàng đầu. Ngoài sự phát triển của các vi sinh vật kháng nhiều loại thuốc, thường có các tác\ndụng phụ và/hoặc biến chứng đối với việc điều trị bằng thuốc kháng khuẩn, bao gồm cả việc mắc phải\nClostridioides difficile (C. diff), tổn thương thận hoặc gan, mất thính lực, thiếu máu tan máu và các biến\nchứng khác như vậy. Việc sử dụng thuốc kháng khuẩn đúng cách rất quan trọng trong việc ngăn ngừa các\nbiến chứng không đáng có do sử dụng thuốc kháng khuẩn không đúng cách.\n\nCác bác sĩ đang góp phần vào sự phát triển của tình trạng kháng thuốc kháng sinh theo nhiều cách (ví dụ, sử dụng\nthuốc kháng sinh khi không được chỉ định; tiếp tục sử dụng thuốc kháng sinh khi không còn cần thiết; sử dụng thuốc\nkháng sinh phổ rộng khi không cần thiết hoặc tiếp tục sử dụng không cần thiết sau khi nhận được kết quả độ nhạy;\nsử dụng thuốc kháng sinh không đúng hoặc kê đơn sai liều hoặc tiếp tục sử dụng thuốc kháng sinh dự phòng sau khi\nkhông còn được khuyến cáo).\n\nĐể giảm sự phát triển và lây lan của các vi sinh vật kháng thuốc và mang lại kết quả tốt hơn cho bệnh nhân, các bệnh\nviện phải thực hiện các biện pháp để đảm bảo sử dụng thuốc kháng sinh hợp lý. Việc triển khai chương trình quản lý\nthuốc kháng sinh sẽ giúp các bệnh viện đạt được mục tiêu cung cấp cho bệnh nhân cần điều trị bằng thuốc kháng sinh\nđúng loại, khi được chỉ định, đúng thời điểm, đúng liều lượng và đúng thời gian. Chương trình bao gồm các hướng\ndẫn về cách sử dụng tối ưu liệu pháp kháng sinh để điều trị các bệnh nhiễm trùng được lựa chọn và/hoặc có nguy cơ\ncao như nhiễm trùng huyết, viêm phổi, viêm nội tâm mạc, viêm màng não, nhiễm trùng đường tiết niệu (UTI) và\nnhiễm trùng do vi khuẩn đa kháng thuốc (MDRO). Các hướng dẫn cũng sẽ bao gồm việc sử dụng thuốc kháng sinh\ndự phòng hợp lý.\n\nChương trình quản lý thuốc kháng khuẩn có thể bao gồm các yếu tố sau: theo dõi chỉ định cho tất cả hoặc một số loại\nthuốc kháng khuẩn được kê đơn, theo dõi các mô hình thực hành kê đơn thuốc kháng khuẩn, theo dõi xu hướng\nkháng thuốc kháng khuẩn bằng kháng sinh đồ, thông báo cho nhân viên về việc sử dụng thuốc kháng khuẩn và tình\ntrạng kháng thuốc thường xuyên và giáo dục nhân viên về cách sử dụng thuốc kháng khuẩn tối ưu. Nhiều chương\ntrình quản lý thuốc kháng khuẩn cũng theo dõi xu hướng Clostridioides difficile như một dấu hiệu thay thế và lập danh\nsách các loại thuốc kháng khuẩn bị hạn chế cần được phê duyệt trước. Điều bắt buộc đối với chương trình là phải có\nsự hỗ trợ của các nhà lãnh đạo bệnh viện - bao gồm cam kết của các nhà lãnh đạo trong việc cung cấp hỗ trợ bao gồm\nnhân sự, nguồn lực tài chính, nguồn lực dựa trên bằng chứng và công nghệ - để đảm bảo một chương trình quản lý\nhiệu quả. Ngoài các chuyên gia phòng ngừa và kiểm soát nhiễm trùng, chương trình quản lý thuốc kháng khuẩn còn có\nsự tham gia của các bác sĩ, y tá, dược sĩ, thực tập sinh và những người khác.\n\nĐể theo dõi hiệu quả của chương trình thành công, cần có cơ chế giám sát. Giám sát có thể bao gồm một cá nhân, một\nnhóm làm việc nhỏ, một nhóm liên ngành phối hợp, một lực lượng đặc nhiệm, một tiểu ban thuốc kháng khuẩn hoặc\nmột số cơ chế khác. Ví dụ về các chiến lược để tối ưu hóa việc kê đơn thuốc kháng khuẩn bao gồm:\n• Phê duyệt trước cho việc sử dụng thuốc kháng khuẩn nói chung và cụ thể bao gồm quy trình xem xét và phê duyệt\nnội bộ trước khi sử dụng\n• Đánh giá và phản hồi dự kiến về các hoạt động kê đơn thuốc kháng khuẩn, bao gồm cả việc điều trị các mẫu cấy\nmáu dương tính, của một thành viên trong chương trình quản lý thuốc kháng khuẩn\n• Theo dõi, xu hướng và phân tích các trường hợp vi khuẩn kháng nhiều loại thuốc\n• Theo dõi, xu hướng và phân tích các mẫu đơn thuốc và lượng thuốc kháng khuẩn hạn chế được sử dụng trong danh\nsách của bệnh viện\n\nTheo dõi hiệu quả của chương trình là một yếu tố quan trọng để chương trình thành công. Ví dụ về dữ liệu có thể\ngiúp đo lường hiệu quả bao gồm:\n• Tất cả việc sử dụng thuốc kháng khuẩn (chung và hạn chế)\n• Bằng chứng về việc giảm sử dụng thuốc kháng khuẩn không phù hợp và giảm vi khuẩn kháng nhiều loại thuốc\n• Tài liệu chứng minh rằng người kê đơn đang tuân theo các hướng dẫn thực hành lâm sàng được chấp nhận\n• Sử dụng thuốc kháng khuẩn dự phòng tối ưu và phù hợp\n• Theo dõi xu hướng Clostridioides difficile như một dấu hiệu thay thế\n• Lập danh sách thuốc kháng khuẩn hạn chế và theo dõi mô hình kê đơn và lượng thuốc sử dụng","m":[],"sec":"Tổ chức và Quản lý"},{"c":"MMU.01.02","ch":"MMU","t":"Bệnh viện có quy trình hệ thống thu hồi thuốc.","p":"Bệnh viện phải đảm bảo rằng họ có quy trình tiếp nhận thông báo về việc thu hồi thuốc và xác định, thu hồi và\ntrả lại hoặc tiêu hủy an toàn và đúng cách các loại thuốc do nhà sản xuất hoặc nhà cung cấp thu hồi khi phát\nhiện ra rằng thuốc bị lỗi hoặc có khả năng gây hại. Các lỗi sản phẩm có thể liên quan đến bao bì không đúng,\nkhả năng nhiễm bẩn hoặc sản xuất kém, dẫn đến tạp chất hoặc lỗi về độ mạnh/hiệu lực. Đôi khi, việc thu hồi\nđược khởi xướng bởi nhà sản xuất, người xác định vấn đề với thuốc và tự nguyện thu hồi thuốc. Những lần\nkhác, một cơ quan chính phủ sẽ yêu cầu thu hồi thuốc sau khi nhận được báo cáo về các vấn đề từ công chúng.\nBệnh viện có thể nhận thông tin liên lạc về việc thu hồi thuốc trực tiếp từ nhà sản xuất hoặc từ các cơ quan\nquản lý. Quy trình thu hồi bao gồm bất kỳ loại thuốc nào được pha chế trong bệnh viện mà các sản phẩm đã bị\nthu hồi đã được sử dụng. Bệnh viện có quy trình thông báo cho các nhà cung cấp dịch vụ chăm sóc sức khỏe về\nviệc thu hồi và tư vấn cho họ về các phương pháp điều trị thay thế, nếu cần, cũng như thông báo cho những\nbệnh nhân đã nhận được thuốc bị thu hồi và cung cấp hướng dẫn phù hợp khi cần. Khung thời gian để thông\nbáo cho các nhà cung cấp dịch vụ chăm sóc sức khỏe và bệnh nhân về việc thu hồi là theo chính sách của bệnh\nviện, khuyến nghị của nhà sản xuất và luật pháp và quy định của địa phương.","m":[],"sec":"Tổ chức và Quản lý"},{"c":"MMU.01.03","ch":"MMU","t":"Bệnh viện có quy trình xử lý thuốc hết hạn.","p":"Bệnh viện phải đảm bảo rằng họ có quy trình nhận dạng, thu hồi và trả lại hoặc loại bỏ an toàn và đúng cách các\nloại thuốc đã hết hạn. Có một chính sách hoặc quy trình giải quyết bất kỳ việc sử dụng hoặc tiêu hủy nào đối\nvới các loại thuốc đã biết là hết hạn hoặc lỗi thời. Thuốc hết hạn là thuốc đã quá ngày hết hạn được liệt kê trên\nbao bì gốc của nhà sản xuất. \"Hạn sử dụng\" (BUD) là ngày và/hoặc thời gian sau đó sản phẩm không được sử\ndụng. Thuốc \"hạn sử dụng\" được định nghĩa là thuốc đã mở hoặc không được sử dụng ở dạng hoặc điều kiện\nban đầu mà nhà sản xuất cung cấp và thường an toàn và hiệu quả để sử dụng trong một thời gian ngắn sau khi\nmở (hạn sử dụng). Điều này sẽ áp dụng cho thuốc được bảo quản lạnh có thời gian sử dụng bên ngoài tủ lạnh\nhoặc lọ insulin được mở và sử dụng trong 28 ngày hoặc hỗn hợp vô trùng được pha chế bằng các thành phần\nkhác. Các loại thuốc \"hạn sử dụng\" này phải được đánh dấu ngày hết hạn dựa trên thời điểm mở để nhân viên\nbiết ngày kết thúc sử dụng.","m":[],"sec":"Tổ chức và Quản lý"},{"c":"MMU.02.00","ch":"MMU","t":"Bệnh viện thực hiện quy trình lựa chọn và mua sắm thuốc.","p":"Bệnh viện có phương pháp giám sát danh mục thuốc của bệnh viện, bao gồm cách sử dụng thuốc đã liệt kê; phương\npháp đảm bảo thuốc kê đơn hoặc đặt hàng được dự trữ; và quy trình mua thuốc không có trong kho hoặc không có\nsẵn tại bệnh viện hoặc trong thời gian hiệu thuốc đóng cửa. Các phương pháp và quy trình này tồn tại để hỗ trợ sứ\nmệnh của bệnh viện, nhu cầu của bệnh nhân và các loại dịch vụ được cung cấp.\n\nMỗi bệnh viện phải quyết định loại thuốc nào sẽ được các bác sĩ kê đơn và đặt hàng. Bệnh viện lập danh sách\n(thường được gọi là danh mục thuốc) gồm tất cả các loại thuốc mà bệnh viện dự trữ hoặc có sẵn từ các dịch vụ theo\nhợp đồng. Trong một số trường hợp, luật pháp và quy định có thể xác định các loại thuốc trong danh mục hoặc\nnguồn gốc của các loại thuốc đó. Việc lựa chọn thuốc là một quy trình hợp tác bao gồm nhu cầu và sự an toàn của\nbệnh nhân cũng như kinh tế. Thuốc đôi khi hết hàng do giao hàng chậm trễ, tình trạng thiếu hụt thuốc trên toàn\nquốc hoặc các lý do khác không lường trước được thông qua việc kiểm soát hàng tồn kho thông thường.\n\nBệnh viện có phương pháp, chẳng hạn như chỉ định một nhóm liên ngành, để duy trì và theo dõi danh mục thuốc và\ntheo dõi việc sử dụng thuốc trong bệnh viện; ví dụ, theo dõi việc sử dụng\nthuốc kháng khuẩn. Những người tham gia giám sát danh sách bao gồm các bác sĩ chăm sóc sức khỏe tham gia vào\nquá trình đặt hàng, phân phối, quản lý và theo dõi thuốc. Nhóm liên ngành báo cáo các phát hiện, khuyến nghị và\ntình trạng chương trình của mình cho các nhà lãnh đạo bệnh viện. Tiêu chí để lựa chọn thuốc bao gồm, tối thiểu,\nnhững điều sau:\n•\nChỉ định sử dụng\n•\nHiệu quả\n•\nTương tác thuốc\n•\nKhả năng xảy ra lỗi và lạm dụng\n•\nCác tác dụng phụ của thuốc\n•\nCảnh báo về sự kiện quan trọng\n•\nNhóm đối tượng được phục vụ (ví dụ: nhi khoa, lão khoa)\n•\nCác rủi ro khác\n•\nChi phí\n\nCó một quy trình hoặc cơ chế để theo dõi phản ứng của bệnh nhân đối với các loại thuốc mới được thêm vào. Ví\ndụ, khi quyết định thêm một loại thuốc mới hoặc một nhóm thuốc mới vào danh sách, sẽ có một quy trình\nđể thu thập, tổng hợp và theo dõi dữ liệu liên quan đến tính phù hợp của chỉ định, cách kê đơn thuốc\n(ví dụ như liều lượng hoặc đường dùng) và bất kỳ tác dụng phụ hoặc tình trạng bất lợi nào không lường trước\nđược liên quan đến thuốc mới trong giai đoạn giới thiệu. Danh sách được xem xét ít nhất hàng năm dựa trên thông\ntin mới về tính an toàn và hiệu quả và thông tin về cách sử dụng và tác dụng phụ.\n\nĐôi khi, cần có thuốc không có sẵn hoặc không có sẵn tại bệnh viện, và sẽ có một quy trình để phê duyệt và mua các\nloại thuốc đó. Ví dụ, những bệnh nhân đang truyền dịch tại nhà trở thành bệnh nhân nội trú có thể không có đủ\nthuốc để tiếp tục truyền dịch trong khi nằm viện. Các loại thuốc đặc trị như vậy có thể bao gồm các loại thuốc\ntruyền cứu sống cho bệnh tăng huyết áp phổi và các loại thuốc được sử dụng trong máy bơm insulin. Sẽ có một quy\ntrình để phê duyệt và mua các loại thuốc đó. Ngoài ra, có những trường hợp cần dùng thuốc vào ban đêm hoặc khi\nhiệu thuốc đóng cửa. Mỗi bệnh viện cần lập kế hoạch cho những trường hợp này và hướng dẫn nhân viên về các\nquy trình cần tuân thủ trong trường hợp chúng xảy ra.","m":[],"sec":"Lựa chọn và mua sắm"},{"c":"MMU.03.00","ch":"MMU","t":"Thuốc được bảo quản đúng cách và an toàn.","p":"Việc giám sát việc lưu trữ thuốc bao gồm tất cả các địa điểm lưu trữ thuốc để đảm bảo tính nhất quán với độ ổn định\ncủa sản phẩm và bảo vệ khỏi bị mất hoặc trộm cắp. Thuốc có thể được lưu trữ trong khu vực lưu trữ, tại hiệu thuốc\nhoặc dịch vụ dược phẩm, tại các đơn vị chăm sóc bệnh nhân, tại các hiệu thuốc của đơn vị hoặc trạm điều dưỡng tại\nđơn vị lâm sàng.\n\nCó một số loại thuốc cần được xử lý đặc biệt, như các ví dụ sau:\n• Thuốc phóng xạ gây ra rủi ro về an toàn.\n• Thuốc chống ung thư và các loại thuốc nguy hiểm khác gây rủi ro cho nhân viên chăm sóc sức khỏe xử lý,\nchuẩn bị, phân phối, quản lý hoặc thải bỏ các loại thuốc này.\n• Thuốc đang trong quá trình nghiên cứu có thể cần được lưu trữ đặc biệt và/hoặc sự đồng ý.","m":[],"sec":"Lưu trữ"},{"c":"MMU.03.01","ch":"MMU","t":"Thuốc cấp cứu luôn có sẵn, được lưu trữ đồng đều, được theo dõi và an toàn khi cất giữ bên ngoài hiệu thuốc.","p":"Việc tiếp cận nhanh chóng với các loại thuốc cấp cứu phù hợp là rất quan trọng khi xảy ra tình trạng cấp\ncứu cho bệnh nhân. Mỗi bệnh viện đều lập kế hoạch về vị trí thống nhất của các loại thuốc cấp cứu, giúp\ntiếp cận nhanh chóng với đúng loại thuốc trong trường hợp cấp cứu. Hồi sức cấp cứu là tình huống rất căng\nthẳng và nhạy cảm về thời gian. Do đó, nguy cơ xảy ra lỗi dùng thuốc trong quá trình hồi sức cấp cứu có thể\ncao hơn. Viện Thực hành Thuốc an toàn (ISMP) xác định rằng các yếu tố thường được báo cáo góp phần\nvào nguy cơ mắc lỗi cao hơn này bao gồm:\n• Bao bì sản phẩm hoặc tên thuốc giống nhau\n• Xe đẩy cấp cứu không có tổ chức và không chuẩn hóa\n• Quá nhiều hàng trong xe đẩy cấp cứu\n• Sự mất tập trung do môi trường bận rộn\n• Các lệnh bằng lời nói không được truyền đạt tốt\n• Nhân viên thiếu kinh nghiệm\n• Thuốc thay thế trong xe đẩy cấp cứu\n• Thông tin về thuốc gây nhầm lẫn hoặc thiếu\n• Nhiều nồng độ thuốc trong ngăn kéo xe đẩy cấp cứu\nDo đó, khi xảy ra tình trạng cấp cứu cho bệnh nhân, việc tiếp cận nhanh chóng với các loại thuốc cấp cứu\nphù hợp là rất quan trọng. Mỗi bệnh viện đều lập kế hoạch về vị trí của các loại thuốc cấp cứu và các loại\nthuốc sẽ được cung cấp dựa trên nhóm dân số được phục vụ. Ví dụ, các tác nhân để đảo ngược gây mê được\ntìm thấy trong các phòng phẫu thuật. Tủ, xe đẩy, túi hoặc hộp cấp cứu có thể được sử dụng cho mục đích\nnày. Thuốc cấp cứu được lưu trữ đồng nhất để tạo điều kiện tiếp cận nhanh chóng với đúng loại thuốc. Ví\ndụ, trong mỗi xe cấp cứu trong bệnh viện, thuốc cấp cứu được để trong cùng một ngăn kéo và thuốc được\nsắp xếp theo cùng một cách trong ngăn kéo của mỗi xe. Điều này đặc biệt quan trọng đối với nhân viên có\nthể cần tiếp cận thuốc cấp cứu từ xe mà họ không thường sử dụng. Việc lưu trữ thuốc trong xe cấp cứu nhi\nkhoa khác với xe cấp cứu người lớn; tuy nhiên, thuốc được lưu trữ đồng nhất trong mỗi loại xe. Mặc dù các\nloại thuốc cấp cứu thông thường được sử dụng trong hồi sức nhi khoa không khác so với các loại thuốc\nđược sử dụng trong hồi sức người lớn, nhưng liều lượng thường khác nhau và dựa trên cân nặng hoặc yêu\ncầu nồng độ khác nhau, trong khi liều dùng cho người lớn thường (nhưng không phải lúc nào cũng vậy)\nđược dùng theo liều. Ví dụ, liều epinephrine thông thường dùng cho người lớn bị ngừng tim là 1 mg và đối\nvới trẻ em thì liều này dựa trên cân nặng và được khuyến nghị là 0,01 mg/kg theo giao thức Hỗ trợ sự sống\nnâng cao cho trẻ em (AHA PALS) của Hiệp hội Tim mạch Hoa Kỳ. Bệnh viện phải đảm bảo rằng xe cấp cứu\ncũng có các công cụ và nồng độ thuốc cần thiết để tạo điều kiện cho việc định lượng thuốc cho trẻ em trong\ntrường hợp khẩn cấp.\n\nBệnh viện thiết lập một quy trình hoặc quy trình để ngăn ngừa việc lạm dụng, trộm cắp hoặc mất thuốc\nnhằm đảm bảo tiếp cận được thuốc cấp cứu khi cần, cũng như đảm bảo rằng thuốc được thay thế khi đã sử\ndụng, bị hỏng hoặc hết hạn. Ví dụ, việc kết hợp kiểm tra xe cấp cứu vào công việc hàng ngày của nhân viên\nđơn vị có thể giúp đảm bảo tính toàn vẹn của xe và nội dung của xe. Bệnh viện phải hiểu được sự cân bằng\ngiữa khả năng tiếp cận dễ dàng và an ninh đối với các địa điểm lưu trữ thuốc cấp cứu, nhưng cũng phải lưu\ný rằng việc tiếp cận thuốc cấp cứu không được yêu cầu một cá nhân cụ thể nào đó trong đơn vị mở khóa xe\ncấp cứu. Trong những trường hợp như vậy, nếu cá nhân đó không có mặt, thuốc sẽ không còn dễ dàng tiếp\ncận được nữa, mặc dù chúng có thể được bảo mật.\n\nSự nhất quán và đồng nhất trong cách tiếp cận hồi sức cấp cứu có thể làm giảm đáng kể rủi ro và cải thiện\nkết quả của bệnh nhân. Một ví dụ về chiến lược mà bệnh viện có thể thực hiện là cách tiếp cận dựa trên\nrủi ro để tăng cường an toàn và cải thiện kết quả của bệnh nhân bằng cách xem xét dữ liệu nội bộ từ các\ntình huống khẩn cấp trước đó để xem xét\n\nsự sẵn có của thuốc cấp cứu hoặc xem xét tài liệu công khai về chủ đề này. Ví dụ về các chiến lược được\nxác định trong tài liệu bao gồm những điều sau đây:\n•\nSử dụng chiến lược để phân biệt giữa thuốc dành cho người lớn và thuốc dành cho trẻ em; ví dụ, sử dụng\nxe đẩy riêng cho người lớn và trẻ em hoặc khi sử dụng xe đẩy chung, hãy cất thuốc và thiết bị trong các\nngăn kéo riêng cho người lớn và trẻ em.\n•\nGiữ một hộp thuốc dành riêng cho trẻ sơ sinh ở những khu vực chăm sóc trẻ sơ sinh.\n•\nChuẩn hóa cách bố trí xe đẩy và ngăn kéo trong toàn bộ bệnh viện.","m":[],"sec":"Lưu trữ"},{"c":"MMU.04.00","ch":"MMU","t":"Bệnh viện xác định những cá nhân đủ điều kiện được phép kê đơn hoặc yêu cầu thuốc.","p":"Mỗi bệnh viện có trách nhiệm xác định những cá nhân có đủ kiến thức và kinh nghiệm cần thiết và cũng\nđược phép theo giấy phép, chứng nhận, luật hoặc quy định để kê đơn hoặc yêu cầu thuốc. Việc lựa chọn\nthuốc để điều trị cho bệnh nhân đòi hỏi phải có kiến thức và kinh nghiệm cụ thể. Bệnh viện có thể đặt ra\ncác giới hạn về việc kê đơn hoặc yêu cầu thuốc của một cá nhân, chẳng hạn như đối với các chất được\nkiểm soát, tác nhân hóa trị hoặc thuốc phóng xạ và thuốc đang nghiên cứu. Những cá nhân được phép kê\nđơn và yêu cầu thuốc phải được dịch vụ dược phẩm hoặc những người khác phân phối thuốc biết đến.\nTrong các tình huống khẩn cấp, bệnh viện sẽ xác định bất kỳ cá nhân nào khác được phép kê đơn hoặc yêu\ncầu thuốc.","m":[],"sec":"Đặt hàng và kê đơn"}];})(window);
